INSERT INTO curriculum_assessment_strategies (id, subject, grade_level, strand, elo_number, strategy_type, strategy_category, description, sort_order, created_at, updated_at) VALUES
  ('a31b8444-9434-4931-884a-178262f306af', 'mathematics', '1', 'Geometrical Thinking', '1.1', 'observation', 'Shape Identification', 'Observe and monitor students as they identify 2D shapes and 3D objects in pictures or in real-world context', 1, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('e72b25f4-86f4-43fd-be9f-2e68ab3fa26d', 'mathematics', '1', 'Geometrical Thinking', '1.1', 'observation', 'Real-World Context', 'Can the student identify shapes in real-world objects, such as in a classroom, playground, or home?', 2, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('4af0e926-f49c-44c7-b707-512963b0c6ee', 'mathematics', '1', 'Geometrical Thinking', '1.1', 'observation', 'Real-World Context', 'Can the student name the shapes they see correctly?', 3, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('94e1d109-b688-4a05-bf89-3183393efe5e', 'mathematics', '1', 'Geometrical Thinking', '1.1', 'observation', 'Real-World Context', 'Can the student identify the characteristics of each shape (number of sides, corners, curves, etc.)?', 4, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('67416cb6-866d-4817-a48a-ff7b2cfcc874', 'mathematics', '1', 'Geometrical Thinking', '1.1', 'observation', 'Real-World Context', 'Can the student identify shapes from different perspectives (e.g., recognizing a triangle when it is upside down)?', 5, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('31f1fcd7-fa81-4eb5-9454-3099de55aa93', 'mathematics', '1', 'Geometrical Thinking', '1.1', 'checklist', '2D Shapes', 'Checklist criteria: Can the student identify the 2D shapes correctly?', 6, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('11fb5fb0-ebbc-4273-b06b-fcd85741d114', 'mathematics', '1', 'Geometrical Thinking', '1.1', 'checklist', '2D Shapes', 'Checklist criteria: Can the student sort the 2D shapes into the correct category (circle, triangle, square, rectangle)?', 7, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('173b1c34-acc4-4bc6-ae7a-26a11bb4c9a1', 'mathematics', '1', 'Geometrical Thinking', '1.1', 'checklist', '2D Shapes', 'Checklist criteria: Does the student understand the concept of flatness in 2D shapes?', 8, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('10bc99e8-ef4a-4f9c-9f98-bccbf09f217e', 'mathematics', '1', 'Geometrical Thinking', '1.1', 'checklist', '3D Objects', 'Checklist criteria: Can the student identify the 3D objects correctly?', 9, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('b7c57cd9-b27a-4f4c-a482-3578b3c9000e', 'mathematics', '1', 'Geometrical Thinking', '1.1', 'checklist', '3D Objects', 'Checklist criteria: Can the student sort the 3D objects into the correct category (sphere, cube, cone, cylinder)?', 10, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('476bb414-1a90-434c-a49a-544838e3855a', 'mathematics', '1', 'Geometrical Thinking', '1.1', 'checklist', '3D Objects', 'Checklist criteria: Does the student understand the concept of depth in 3D objects?', 11, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('cff94966-f936-49f0-b7d4-b3c309740568', 'mathematics', '1', 'Geometrical Thinking', '1.1', 'checklist', '3D Objects', 'Checklist criteria: Can the student identify the number of faces, edges, and vertices of each 3D object?', 12, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('fe2ef8ff-96e1-42fe-ab70-e5cba4e7a51e', 'mathematics', '1', 'Geometrical Thinking', '1.1', 'interview', 'General', 'Conduct interviews with students to assess their understanding of shapes and space. Ask open-ended questions and encourage students to use descriptive language and gestures', 13, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('49127f99-5872-40ed-9639-eb1ecc5b2ab7', 'mathematics', '1', 'Geometrical Thinking', '1.1', 'interview', '2D Shape Questions', 'Sample question: Can you tell me the names of some 2D shapes that you know?', 14, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('ad000330-8971-46ed-b34b-7d1d29192eb9', 'mathematics', '1', 'Geometrical Thinking', '1.1', 'interview', '2D Shape Questions', 'Sample question: Can you show me a 2D shape using your hands or fingers? What is it called?', 15, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('c23dbca7-c12a-48c6-b38f-b0802f16c8c5', 'mathematics', '1', 'Geometrical Thinking', '1.1', 'interview', '2D Shape Questions', 'Sample question: What is the difference between a circle and a square? Can you show me with your hands or draw it on paper?', 16, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('ce67f43b-77c0-4cb4-8ede-dce80844febd', 'mathematics', '1', 'Geometrical Thinking', '1.1', 'interview', '3D Shape Questions', 'Sample question: Can you tell me the names of some 3D shapes that you know?', 17, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('228a7a57-c89d-4f99-8258-8d9f91f858e2', 'mathematics', '1', 'Geometrical Thinking', '1.1', 'interview', '3D Shape Questions', 'Sample question: Can you show me a 3D shape using toys or objects? What is it called?', 18, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('4bb2b802-acb3-4d7b-a56d-99238946bef4', 'mathematics', '1', 'Geometrical Thinking', '1.1', 'interview', '3D Shape Questions', 'Sample question: How do 3D shapes differ from 2D shapes? Can you show me with your hands or draw it on paper?', 19, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('aa69bc71-976b-42c5-97cb-3e6cbb9bee22', 'mathematics', '1', 'Geometrical Thinking', '1.1', 'interview', 'Real-Life Application', 'Sample question: Can you describe a real-life object that is shaped like a cylinder?', 20, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('c55487e6-8f44-44de-9a1a-edeeddb5c30f', 'mathematics', '1', 'Geometrical Thinking', '1.1', 'interview', 'Real-Life Application', 'Sample question: Can you tell me what a cube looks like and give me an example of a real-life object shaped like a cube?', 21, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('9f8e2684-7ac9-4d2e-8454-fb41ae401a57', 'mathematics', '1', 'Geometrical Thinking', '1.1', 'interview', 'Connection Questions', 'Sample question: How do shapes and space relate to each other? Can you give me an example of how shapes are used in our daily lives?', 22, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('b471aeb1-e5c8-464c-99eb-76d67bb4db5f', 'mathematics', '1', 'Geometrical Thinking', '1.1', 'interview', 'Connection Questions', 'Sample question: Can you think of a fun activity we can do to learn more about shapes and space?', 23, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('4189adbc-9f6f-42ea-9d65-706911689cb6', 'mathematics', '1', 'Geometrical Thinking', '1.1', 'checklist', 'Hidden Shapes', 'Observe students using a checklist as they find shapes or paths hidden in a picture or space', 24, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('6f89b92c-ab48-4f94-ae3a-72b48053d30c', 'mathematics', '1', 'Geometrical Thinking', '1.1', 'checklist', 'Hidden Shapes', 'Checklist item: Can the student locate an object in a simple picture?', 25, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('15617822-3e35-4b40-acb7-289664b89141', 'mathematics', '1', 'Geometrical Thinking', '1.1', 'checklist', 'Hidden Shapes', 'Checklist item: Can the student complete a maze?', 26, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('1da9e002-29a1-424d-b658-f55e4a1b1911', 'mathematics', '1', 'Geometrical Thinking', '1.1', 'checklist', 'Hidden Shapes', 'Question students about shapes or paths hidden in a picture or space', 27, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('65fcba6c-cd24-4db4-9702-273d6fc39465', 'mathematics', '1', 'Number Sense', '1.1', 'observation', 'Concrete', 'Check to see whether learners can use manipulatives to count and build quantities up to 20', 1, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('b3ff6bd7-1d3e-40fb-8e97-eb9483f52a11', 'mathematics', '1', 'Number Sense', '1.1', 'observation', 'Concrete', 'Observe learners write the numeral in figures and words after being shown a representation of a particular quantity up to 20', 2, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('64aebcf0-4cdb-4192-8c61-0b306d387cb7', 'mathematics', '1', 'Number Sense', '1.1', 'observation', 'Concrete', 'Allow learners to use manipulatives, interactive games and number lines to identify errors in a counting sequence up to 20', 3, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('00c36085-60d8-462d-a10a-d6e8b6d956ba', 'mathematics', '1', 'Number Sense', '1.1', 'observation', 'Pictorial', 'Observe learners as they match pictorial representation of quantities with the correct number up to 20', 4, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('3306c426-024e-47fe-900f-e4867351a769', 'mathematics', '1', 'Number Sense', '1.1', 'observation', 'Pictorial', 'Allow learners to draw quantities to represent a given amount up to 20', 5, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('763a835d-d932-46a5-b7b7-ab86b0d0b45a', 'mathematics', '1', 'Number Sense', '1.1', 'observation', 'Pictorial', 'Check as learners use vertical and horizontal number lines to count forward to 100 by 1s, 2s, 5s and 10s and forward and backwards from 20 by 1s, 2s, 5s and 10', 6, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('f6d67acb-170c-457f-b215-f81d110d0abc', 'mathematics', '1', 'Number Sense', '1.1', 'observation', 'Symbolic', 'Listen to learners as they call out numerals based on a representation shown of a particular quantity up to 20', 7, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('c3435c5f-7ca0-4a24-8d3f-2800b4cf4129', 'mathematics', '1', 'Number Sense', '1.1', 'observation', 'Symbolic', 'Listen to learners as they count in sequence to 100', 8, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('94a12255-2706-49d0-956d-c17a375169f9', 'mathematics', '1', 'Number Sense', '1.1', 'think-pair-share', 'General', 'Have learners select a card of their choice then pair with each other to match the symbolic representation of the quantity shown on their card', 1, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('b879040b-33b7-48e7-8d7e-4daf90333a86', 'mathematics', '1', 'Number Sense', '1.1', 'talking-circles', 'General', 'Learners form a circle and take turns to skip count', 1, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('af9d7717-8948-496f-8643-af999d9e24a6', 'mathematics', '1', 'Number Sense', '1.1', 'talking-circles', 'General', 'Allow learners to come up with their own sequence up to 20 and explain to the class how they formed that sequence', 2, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('1f5d4e8f-074d-4475-90de-799eeea0719c', 'mathematics', '1', 'Number Sense', '1.1', 'product', 'Group Work', 'In groups, allow learners to form sets of 2s and 5s with objects given (up to 20). Learners will then count the number of groups made in each case', 1, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('44c04a24-85d9-469f-8d70-ce6b57d6baaf', 'mathematics', '1', 'Number Sense', '1.1', 'product', 'Group Work', 'Using manipulatives, allow learners to form sets up to 20 and match numerals for each set', 2, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('4ad480f1-4808-4c92-99eb-0c6cdceacfb5', 'mathematics', '1', 'Number Sense', '1.1', 'product', 'Group Work', 'As groups, learners fish for numerals up to 20 and draw quantities to represent the numeral', 3, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('450bdcbc-4bf9-48bb-856e-ad7c89568d04', 'mathematics', '1', 'Number Sense', '1.1', 'exit-ticket', 'General', 'Ask learners to draw a picture showing the number of cupcakes in 4 packages if there are three cupcakes in each package', 1, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('2a1e0bc5-ba85-4781-88a8-77fa01840790', 'mathematics', '1', 'Number Sense', '1.1', 'exit-ticket', 'General', 'Using given sets of manipulatives, allow learners to count and state the final number for each set', 2, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('d3e59c65-b026-45e7-b7fe-cd159f277e2b', 'mathematics', '1', 'Number Sense', '1.1', 'diagnostic', 'Questions', 'Are students able to recite number sequences beginning with 1, 2, 3, 4, 5, 6, 7… etc.?', 1, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('c4bdb389-3476-4893-94cb-c94412d43a6e', 'mathematics', '1', 'Number Sense', '1.1', 'diagnostic', 'Questions', 'Are students able to count using one to one correspondence?', 2, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('7fe452b6-8915-4b6e-8404-c567d5b27532', 'mathematics', '1', 'Number Sense', '1.1', 'diagnostic', 'Questions', 'Can students identify the number that comes after or before a number from 1-20?', 3, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('6f07a2ca-c329-45ab-a701-b9be445f2015', 'mathematics', '1', 'Number Sense', '1.1', 'diagnostic', 'Questions', 'Are students able to skip count in 2''s, 5''s and 10''s on a number line?', 4, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('7dada071-d284-4258-8a1b-f108e6451f6e', 'mathematics', '1', 'Number Sense', '1.1', 'diagnostic', 'Questions', 'Can students recognize 0 as the absence of items in a set? As a starting point for counting on the number line?', 5, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('4e9819b3-0aef-4dbf-8a74-ad921c08919b', 'mathematics', '1', 'Number Sense', '1.1', 'error-identification', 'General', 'Circle the number that is in the wrong place in each row: a) 5, 6, 7, 8, 4  b) 1, 5, 2, 3, 4  c) 11, 12, 13, 15, 14, 16, 17  d) 10, 9, 8, 7, 6, 4, 5, 3  e) 20, 19, 18, 16, 17, 15', 1, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('f17f74a5-80ad-4893-9e6c-ba5d326bccc4', 'mathematics', '1', 'Number Sense', '1.2', 'observation', 'Concrete', 'Observe learners as they work with concrete materials. Are they able to represent numbers accurately?', 1, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00');
INSERT INTO curriculum_assessment_strategies (id, subject, grade_level, strand, elo_number, strategy_type, strategy_category, description, sort_order, created_at, updated_at) VALUES
  ('f2da9b43-3376-45a7-9486-20ca851f0243', 'mathematics', '1', 'Number Sense', '1.2', 'observation', 'Concrete', 'Check to see if learners are making use of resources correctly', 2, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('44b5a174-1cf1-4284-96b1-cb28bc296f4e', 'mathematics', '1', 'Number Sense', '1.2', 'observation', 'Pictorial', 'Observe students as they make pictorial representation of numbers. Have them explain representations', 3, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('31680f41-4f7a-42be-b691-5b243b4d5218', 'mathematics', '1', 'Number Sense', '1.2', 'observation', 'Pictorial', 'Count the stars, then colour the same amount in the ten frames', 4, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('155520f8-8a5d-4375-8931-657ae5505cb5', 'mathematics', '1', 'Number Sense', '1.2', 'observation', 'Pictorial', 'Students will match the number card to the ten-frame representation', 5, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('502b87fe-a807-4943-a1c1-d5f3b557cdef', 'mathematics', '1', 'Number Sense', '1.2', 'product', 'Group Work', 'Observe as they find examples of given numbers in the environment', 1, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('bc783026-de44-4db3-8df0-b2ef3b73e471', 'mathematics', '1', 'Number Sense', '1.2', 'product', 'Group Work', 'Guide students as they label number line or put the numbers in order on a chart', 2, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('59a40be2-0140-404d-9755-86c708bad82c', 'mathematics', '1', 'Number Sense', '1.2', 'think-pair-share', 'General', 'Have students place numbers on a number line with benchmarks', 1, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('6cc0e6d9-a641-44e1-8a0e-b8c4f03c602d', 'mathematics', '1', 'Number Sense', '1.2', 'think-pair-share', 'General', 'Listen to them as they convince their partner that they have placed the numbers on the line correctly', 2, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('ba264c7a-8542-42f1-a2ea-73882fdf63df', 'mathematics', '1', 'Number Sense', '1.2', 'exit-ticket', 'General', 'Have students use two different objects to create a model for a given number', 1, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('7ee359e8-e625-4e81-8a5c-a48aabe00318', 'mathematics', '1', 'Number Sense', '1.2', 'exit-ticket', 'General', 'Have them create a poster using art material or something of that nature', 2, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('09fc9aa1-f712-489f-9cb9-04a9d73cfb53', 'mathematics', '1', 'Number Sense', '1.2', 'subitizing', 'General', 'Subitizing Rings: Write the numerals on each end of the clothespins, and then encourage students to match the numeral on the pin to the matching amount of dots on each of the Subitizing Rings', 1, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('df020eef-6fe2-42ab-8064-60914a7555f0', 'mathematics', '1', 'Number Sense', '1.2', 'subitizing', 'General', 'Challenge them by timing how fast they can match the pins to their correct spots on the ring', 2, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('ad0ef057-e18d-4965-b0c6-160077156dc9', 'mathematics', '1', 'Number Sense', '1.3', 'observation', 'Concrete', 'Check to see whether learners can count manipulatives in two given groups and identify the group with more or the one with fewer', 1, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('5a351a40-4d40-4cfa-a104-a66054bc3880', 'mathematics', '1', 'Geometrical Thinking', '1.1', 'prediction', 'General', 'Students are asked to make predictions about 2D shapes and 3D objects in picture or in real-world context', 28, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('40705d7e-49f4-437d-b6e3-69436809fd1d', 'mathematics', '1', 'Number Sense', '1.3', 'game-based', 'General', 'Students will be placed into groups of 3. Two will dip a number and jump on the number line based on their chosen numbers. The distance (number of squares) jumped by each will be observed and recorded by the 3rd group member', 1, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('a8007767-12c1-43fe-a799-fddb86940ab4', 'mathematics', '1', 'Number Sense', '1.3', 'observation', 'Pictorial', 'Observe students as they count given quantities and identify the larger and smaller group', 2, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('78b4aabe-9280-4fc0-bbd6-7e36da3a24a4', 'mathematics', '1', 'Number Sense', '1.3', 'observation', 'Symbolic', 'Have students count and write numerals based on a representation shown for groups to identify the one that has less or more (students may be given groups with less first or more)', 3, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('30fa2fe2-ca08-44e2-8b23-7893edaa8654', 'mathematics', '1', 'Number Sense', '1.3', 'exit-ticket', 'General', 'In the given columns students will draw one more or less object of a given set', 1, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('42e0aaf6-55b5-46b6-8503-970fdaf5308a', 'mathematics', '1', 'Number Sense', '1.3', 'exit-ticket', 'General', 'Several pictures of different quantities will be presented. Students should look at pictures, count the amount, order them and provide the ordinal position of the picture', 2, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('a23f92ba-ea5c-45c3-854c-c3851675ee10', 'mathematics', '1', 'Number Sense', '1.3', 'product', 'Group Work', 'In groups, students will be given two numbers and be asked to create a set that comes between the numbers. Each group will share their set with the other groups', 1, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('64713694-e75e-47ee-a785-7d843b606ec5', 'mathematics', '1', 'Number Sense', '1.3', 'product', 'Group Work', 'List the ordinal positions going forward as well as in reverse order', 2, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('d2f70790-ce71-4336-a198-d6c17334f7f6', 'mathematics', '1', 'Number Sense', '1.3', 'match-pair-share', 'General', 'Have learners pair with each other to arrange different given coloured objects (e.g., marbles, small balls, eggs etc.) based on assigned ordinal positions', 1, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('8ecf55f9-95c4-4770-8f66-12f5010ff10d', 'mathematics', '1', 'Number Sense', '1.3', 'think-pair-share', 'General', 'Have students work in pairs and choose and write in symbols a number from eleven to nineteen and take that many sticks. Have them count out and make one bundle of ten using the hair tie, then write and draw what they have', 1, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('58e60aa1-fcd9-4ddc-a375-f6484a24533d', 'mathematics', '1', 'Number Sense', '1.3', 'think-pair-share', 'General', 'Ask the pairs to return to the whole group with their drawings, keeping them hidden. Have the pairs take turns to describe to the class what they have drawn, and ask classmates to say what number it is. The drawing done by the pair will then be shown', 2, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('ae3cc8ad-a9ae-4a26-901b-48258a74f524', 'mathematics', '1', 'Number Sense', '1.3', 'exit-ticket', 'Ordinal Numbers', 'Match ordinal numbers to their numerals', 3, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('5ffff7fb-f0f4-4e91-9809-842edf595c0f', 'mathematics', '1', 'Number Sense', '1.3', 'exit-ticket', 'Ordinal Numbers', 'Write the number that is formed based on ten plus some', 4, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('22f329d7-c568-44fe-a282-005b01683c20', 'mathematics', '1', 'Number Sense', '1.3', 'self-assessment', 'General', 'Use of self-assessment tools and checklist for observable behaviors from students (e.g., students'' attitude while they continue to work in groups and the extent to which students are able to complete tasks)', 1, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('bed1a75d-817e-4b14-9284-c059912aa25a', 'mathematics', '1', 'Number Sense', '1.4', 'entrance-slip', 'General', 'Assess ability to identify and recognize quantities in teens using tens and ones in concrete, pictorial and symbolic forms', 1, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('af63a47f-98e4-41da-81fe-6b4aa2b94b49', 'mathematics', '1', 'Number Sense', '1.4', 'observation', 'Concrete', 'Allow children to count teen numbers using tens and ones', 1, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('6a764844-cf8c-4ed3-9810-e509cd6603a1', 'mathematics', '1', 'Number Sense', '1.4', 'observation', 'Pictorial', 'Introduce The Number Slide. The Number Slide transforms the expanded form numbers (e.g., 10+1, 10+2, etc.) into the conventional number (e.g., 11, 12, etc.)', 2, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('066c70c6-b174-459c-a6aa-e0b485b36f28', 'mathematics', '1', 'Number Sense', '1.4', 'product', 'Group Work', 'In small groups students will be given unit cubes to make stacks of tens which will be traded for a single base ten rod', 1, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('2b40b452-3c32-4332-ad84-9cd4ea85c318', 'mathematics', '1', 'Number Sense', '1.4', 'product', 'Group Work', 'Given other manipulatives such as shells, bottle tops, candies etc. and two plastic glasses of different sizes, students will place only ten in the larger cup and the remainder in the smaller cup and record their findings', 2, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('d2dc031d-531b-429f-aeb5-df62420561fa', 'mathematics', '1', 'Number Sense', '1.4', 'think-pair-share', 'General', 'Learners will be given a group of manipulatives less than 20. Each learner will count the amount given and record it and expand the given amount to represent the amount of tens and ones. The learner will share their findings with the class', 1, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('57d4be06-9b45-4a29-8eb9-c38b70682ffc', 'mathematics', '1', 'Number Sense', '1.4', 'worksheet', 'General', 'Given a worksheet to complete, learners will circle groups of tens and count the remaining as ones', 1, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('44c329cc-9378-47cd-823d-e3e41697b693', 'mathematics', '1', 'Number Sense', '1.4', 'game-based', 'Roll Build Write', 'Roll, Build and Write: Allow students the fun of rolling dice, along with the opportunity to practice building a number with tens and ones', 1, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('e27b86d0-470b-46db-912a-d73168ba7ad8', 'mathematics', '1', 'Number Sense', '1.4', 'game-based', 'I Have Who Has', 'I Have / Who Has: This game is played with an I Have / Who Has deck. Each student gets one card. The person with "start" begins by reading their card. All cards follow the pattern, "I have_____. Who has___?" So a student with 1 tens and 4 ones on their card would say, "I have 14, who has 18?" Then the learner with one ten and eight ones would read their card. Play continues until all students have had a turn or you reach the card that says end.', 2, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('f7be966e-eadb-4456-9a51-d0a0263c85e6', 'mathematics', '1', 'Number Sense', '1.4', 'exit-ticket', 'General', 'Several pictures depicting different quantities are presented: Look at the picture, count the amount and represent it in a mathematical equation', 1, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('44349650-72d1-4251-99db-8a83e938cb9b', 'mathematics', '1', 'Number Sense', '1.4', 'exit-ticket', 'General', 'Generate simple mathematical equations using base ten materials to represent teen numbers (e.g., 16 = 10+6)', 2, '2026-01-06T09:18:33.208022+00:00', '2026-01-06T09:18:33.208022+00:00'),
  ('8517a8d4-a047-4451-bbdb-7c6f71715829', 'mathematics', '1', 'Geometrical Thinking', '1.1', 'prediction', 'Transformation', 'Assess predictions about 2D shapes undergoing a transformation. Example: "Which 2D shape will look the same if it is turned upside down?"', 29, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('04b49323-f688-4232-a055-d6c7d54cb7a6', 'mathematics', '1', 'Geometrical Thinking', '1.1', 'questioning', 'General', 'Ask students questions about shapes, objects, and space to assess their understanding of the concepts', 30, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('e691d272-40bb-4df9-9607-3ea650dc5278', 'mathematics', '1', 'Geometrical Thinking', '1.1', 'questioning', 'Shape Recognition', 'Students are required to identify and name shapes with different size, colour, orientation, as well as when they undergo transformation', 31, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('c6b71cd2-f686-4384-aa4a-ca24ab3e725f', 'mathematics', '1', 'Geometrical Thinking', '1.1', 'questioning', 'Shape Recognition', 'Example question: "Can you identify examples of triangular shapes in the classroom?"', 32, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('e03082ac-2966-4f8a-98bd-97579e9b9662', 'mathematics', '1', 'Operations with Numbers', '1.1', 'entrance-slip', 'Diagnostic', 'Assess students'' ability to match or draw quantities up to 10', 1, '2026-01-06T10:00:46.34638+00:00', '2026-01-06T10:00:46.34638+00:00'),
  ('59f0f02f-fc6b-4195-becc-ae2611d908c6', 'mathematics', '1', 'Operations with Numbers', '1.1', 'entrance-slip', 'Diagnostic', 'Diagnostic check: Can students make multiple representations from a story problem structure?', 2, '2026-01-06T10:00:46.34638+00:00', '2026-01-06T10:00:46.34638+00:00'),
  ('2f08a3fa-8211-4f10-b073-d07831a8dcd7', 'mathematics', '1', 'Operations with Numbers', '1.1', 'observation', 'Concrete', 'Have learners use manipulatives to subtract', 1, '2026-01-06T10:00:46.34638+00:00', '2026-01-06T10:00:46.34638+00:00'),
  ('cf8760f0-4f92-4fbe-8873-9a2641a0bfb4', 'mathematics', '1', 'Operations with Numbers', '1.1', 'observation', 'Concrete', 'Give students 10 buttons and make them take away different quantities from it', 2, '2026-01-06T10:00:46.34638+00:00', '2026-01-06T10:00:46.34638+00:00'),
  ('b9bf542b-4a07-4834-8008-0e0373f23d60', 'mathematics', '1', 'Operations with Numbers', '1.1', 'observation', 'Concrete', 'Check that learners can work out the different number combinations that add up to 10', 3, '2026-01-06T10:00:46.34638+00:00', '2026-01-06T10:00:46.34638+00:00'),
  ('86debba3-dd20-4a47-935d-a448178445ed', 'mathematics', '1', 'Operations with Numbers', '1.1', 'observation', 'Concrete', 'Allow students to place manipulatives on a number line to represent the story being told', 4, '2026-01-06T10:00:46.34638+00:00', '2026-01-06T10:00:46.34638+00:00'),
  ('fa5a7f30-8636-4f21-98f7-6156bd1efb39', 'mathematics', '1', 'Operations with Numbers', '1.1', 'observation', 'Pictorial', 'Learners are introduced using a diagram or picture to communicate an addition equation', 5, '2026-01-06T10:00:46.34638+00:00', '2026-01-06T10:00:46.34638+00:00'),
  ('8ab779dc-a54b-45ac-8fe1-12af73bf6b45', 'mathematics', '1', 'Operations with Numbers', '1.1', 'observation', 'Pictorial', 'Introduce learners to the idea of recording what the diagram shows by allowing them to write the number sentence', 6, '2026-01-06T10:00:46.34638+00:00', '2026-01-06T10:00:46.34638+00:00');
INSERT INTO curriculum_assessment_strategies (id, subject, grade_level, strand, elo_number, strategy_type, strategy_category, description, sort_order, created_at, updated_at) VALUES
  ('06d19395-15c4-4c39-b339-0c77b345d65d', 'mathematics', '2', 'Number Sense', '1.1', 'observation', 'Concrete', 'Check to see whether students can use manipulatives to count and build quantities up to 100. For example, student can use coins to assist in the process. Observation Checklist Students can oCount forward by 1s over the decade oCount backward by 1s over the decadeProvide opportunities for students to experience counting in 1s, 2s, 5s and 10s, to 100 in engaging in real life situations. For example, through games, songs (examples can be found https://www.canteach.ca/', 1, '2025-12-19T03:09:53.600637+00:00', '2025-12-19T03:09:53.600637+00:00'),
  ('60d4dd80-7f9d-45b4-b7c1-3a9ba5af77f9', 'mathematics', '2', 'Patterns and Relationships', '2.1', 'product', 'Group work', 'Can students recognize that a variable may be represented by shapes or objects when finding unknown quantity? Factor Entrance Slip Identify and call out the items in the bowl: 2 red apples, a green apple, one banana Retrieved from https://images.google.com/', 1, '2025-12-19T03:09:53.600637+00:00', '2025-12-19T03:09:53.600637+00:00'),
  ('832a3e18-7181-4a31-9e9b-bd7822b6d4aa', 'mathematics', '1', 'Operations with Numbers', '1.1', 'observation', 'Pictorial', 'Have students use a number line to count back to subtract', 7, '2026-01-06T10:00:46.34638+00:00', '2026-01-06T10:00:46.34638+00:00'),
  ('0ed001aa-0bf4-4035-81f6-397c42d9400f', 'mathematics', '1', 'Operations with Numbers', '1.1', 'observation', 'Symbolic', 'Check that students can write equations to represent their work', 8, '2026-01-06T10:00:46.34638+00:00', '2026-01-06T10:00:46.34638+00:00'),
  ('f1aa362b-b033-4fcd-9894-d556f13c7bb8', 'mathematics', '1', 'Operations with Numbers', '1.1', 'observation', 'Modelling', 'Check that learners can represent the difference between two numbers using concrete materials and diagrams', 9, '2026-01-06T10:00:46.34638+00:00', '2026-01-06T10:00:46.34638+00:00'),
  ('df8c78a4-3159-43c0-bc6c-7aa243a93856', 'mathematics', '1', 'Operations with Numbers', '1.1', 'think-pair-share', 'Think and Share', 'Students will create their own number sentences using manipulatives and tens frame provided and share them with the class', 1, '2026-01-06T10:00:46.34638+00:00', '2026-01-06T10:00:46.34638+00:00'),
  ('257c392f-83f7-4f59-a894-6f53621e9d0f', 'mathematics', '1', 'Operations with Numbers', '1.1', 'think-pair-share', 'General', 'Check that learners can work in pairs to link story problems to the corresponding expression', 2, '2026-01-06T10:00:46.34638+00:00', '2026-01-06T10:00:46.34638+00:00'),
  ('2b3e0684-a9c4-4907-9f12-e3108c158d0d', 'mathematics', '1', 'Operations with Numbers', '1.1', 'think-pair-share', 'General', 'Pairs share with the class and explain why they chose their answer', 3, '2026-01-06T10:00:46.34638+00:00', '2026-01-06T10:00:46.34638+00:00'),
  ('12501775-4aaf-45ce-90af-bf665545b340', 'mathematics', '1', 'Operations with Numbers', '1.1', 'product', 'Playing Games', 'Using an egg carton with a given amount, students will find out how many are needed to fill it, then write the number sentence', 1, '2026-01-06T10:00:46.34638+00:00', '2026-01-06T10:00:46.34638+00:00'),
  ('0b55e2e5-6ed0-4215-96db-d61ae7d47c37', 'mathematics', '1', 'Operations with Numbers', '1.1', 'product', 'Playing Games', 'Allow learners to work in pairs using number grids to answer questions on subtraction by counting back', 2, '2026-01-06T10:00:46.34638+00:00', '2026-01-06T10:00:46.34638+00:00'),
  ('e999b9d2-6b9d-4ac7-a3b0-e3be1503c40f', 'mathematics', '1', 'Operations with Numbers', '1.1', 'product', 'Group Work', 'Make copies of the tens frames and allow students to complete addition equations for stories given', 3, '2026-01-06T10:00:46.34638+00:00', '2026-01-06T10:00:46.34638+00:00'),
  ('eb97c8f8-e8fd-4803-bc93-517aff4a3be1', 'mathematics', '1', 'Operations with Numbers', '1.1', 'product', 'Group Work', 'Number bonds to 10: Learners explore the different number combinations that add up to make 10', 4, '2026-01-06T10:00:46.34638+00:00', '2026-01-06T10:00:46.34638+00:00'),
  ('9773ab92-d877-4b17-9cd8-905a258602ab', 'mathematics', '1', 'Operations with Numbers', '1.1', 'product', 'Group Work', 'Check that learners can work out the different number combinations that add up to 10', 5, '2026-01-06T10:00:46.34638+00:00', '2026-01-06T10:00:46.34638+00:00'),
  ('dcf759c0-4697-4f51-98da-aa2a7c5a17e5', 'mathematics', '1', 'Operations with Numbers', '1.1', 'simulation', 'Bus Activity', 'Use caution tape to model a bus with 16 spaces. Probe students by asking: "How many passengers can the bus hold?" and "How do you know?"', 1, '2026-01-06T10:00:46.34638+00:00', '2026-01-06T10:00:46.34638+00:00'),
  ('fd984652-952b-4ae0-a8ef-6f86727035b8', 'mathematics', '1', 'Operations with Numbers', '1.1', 'simulation', 'Bus Activity', 'Place students in the taped area and ask: "How many passengers are on the bus?" and "The bus needs to be filled. How many more passengers do we need?"', 2, '2026-01-06T10:00:46.34638+00:00', '2026-01-06T10:00:46.34638+00:00'),
  ('1b4f452e-d8d7-4030-baf2-667fe9355917', 'mathematics', '1', 'Operations with Numbers', '1.1', 'diagnostic', 'Counter Questions', 'How many blue counters are there? (Write 5) And how many red counters are there? (Write 3) 5 and 3 make how many counters? Record the equation 5 + 3 = 8', 1, '2026-01-06T10:00:46.34638+00:00', '2026-01-06T10:00:46.34638+00:00'),
  ('e89560b6-a03d-442f-844c-1752289960eb', 'mathematics', '1', 'Operations with Numbers', '1.1', 'story-problem', 'General', 'Present story: "Grade 1 students are baking cupcakes. Yesterday, they baked 4 cupcakes. Today they baked another 3. How many cupcakes did Grade 1 bake?" Observe as students model with materials', 1, '2026-01-06T10:00:46.34638+00:00', '2026-01-06T10:00:46.34638+00:00'),
  ('dab06216-f732-4df1-8156-3adc50034932', 'mathematics', '1', 'Operations with Numbers', '1.2', 'observation', 'Concrete', 'Have students use manipulatives/pictures to make, draw and/or tell the number amount in a group or set', 1, '2026-01-06T10:00:46.34638+00:00', '2026-01-06T10:00:46.34638+00:00'),
  ('6f12362f-4b02-4811-8eb1-2b68c3b0e31f', 'mathematics', '1', 'Operations with Numbers', '1.2', 'observation', 'Concrete', 'Check to see that learners can build groups using manipulatives', 2, '2026-01-06T10:00:46.34638+00:00', '2026-01-06T10:00:46.34638+00:00'),
  ('15d14aff-a491-4db5-bb4f-4bb22195de0a', 'mathematics', '1', 'Operations with Numbers', '1.2', 'observation', 'Symbolic', 'Have students write symbols (numbers) to represent an amount in a group/set', 3, '2026-01-06T10:00:46.34638+00:00', '2026-01-06T10:00:46.34638+00:00'),
  ('27f8cf73-2059-4167-b0cc-971f3397eaa6', 'mathematics', '1', 'Operations with Numbers', '1.2', 'observation', 'Symbolic', 'Have students write/transfer manipulatives/pictorial addition amounts to symbolic representation', 4, '2026-01-06T10:00:46.34638+00:00', '2026-01-06T10:00:46.34638+00:00'),
  ('95ab42eb-970c-42ba-94e5-aff417d5a313', 'mathematics', '1', 'Operations with Numbers', '1.2', 'whole-class', 'Discussion', 'Class discussion on the symbol (+) of addition. Teacher demonstrates/prompts as students come up with their own words that tell (+) addition', 1, '2026-01-06T10:00:46.34638+00:00', '2026-01-06T10:00:46.34638+00:00'),
  ('b053f392-0614-4fbd-93ea-98515b6f3cc2', 'mathematics', '1', 'Operations with Numbers', '1.2', 'think-pair-share', 'General', 'In small groups, students are given cards or manipulatives to write the symbolic representation of what is on the card or what they made using the manipulatives', 1, '2026-01-06T10:00:46.34638+00:00', '2026-01-06T10:00:46.34638+00:00'),
  ('b5c83353-d283-4e7c-a88c-8a778e36df3c', 'mathematics', '1', 'Operations with Numbers', '1.2', 'exit-ticket', 'Game', 'In pairs, small groups or whole class: students roll two dice, then write symbolic representations showing additive thinking', 1, '2026-01-06T10:00:46.34638+00:00', '2026-01-06T10:00:46.34638+00:00'),
  ('6318b2c2-a0ec-4f12-b6af-4883562918b7', 'mathematics', '2', 'Patterns and Relationships', '1.1', 'product', 'Group work', 'Make predictions as to what may come next in a given pattern. Skills', 1, '2025-12-19T03:09:53.600637+00:00', '2025-12-19T03:09:53.600637+00:00'),
  ('cb8de657-3001-4c95-b328-3fc9d340f396', 'mathematics', '2', 'Patterns and Relationships', '1.1', 'product', 'Group work', 'Create and extend simple patterns with 3 -5 elements.', 2, '2025-12-19T03:09:53.600637+00:00', '2025-12-19T03:09:53.600637+00:00'),
  ('58f7fd41-a563-479a-9f96-98e68751c015', 'mathematics', '2', 'Patterns and Relationships', '1.1', 'product', 'Group work', 'Create patterns resulting from repeating an operation or making a repeated change to an attribute.', 3, '2025-12-19T03:09:53.600637+00:00', '2025-12-19T03:09:53.600637+00:00'),
  ('ca93d50d-ebab-4d33-b2ac-19ebf4b6069b', 'mathematics', '2', 'Patterns and Relationships', '1.1', 'product', 'Group work', 'Copy and extend a repeating pattern (using manipulatives, diagrams, body movements/actions/sounds)', 4, '2025-12-19T03:09:53.600637+00:00', '2025-12-19T03:09:53.600637+00:00'),
  ('6b44f9e2-4cda-4de5-be65-a70237843960', 'mathematics', '2', 'Patterns and Relationships', '1.1', 'product', 'Group work', 'Translate simple repeating patterns (E.g., a repeating orientation pattern to a repeating sound pattern, etc.).', 5, '2025-12-19T03:09:53.600637+00:00', '2025-12-19T03:09:53.600637+00:00'),
  ('4e89c322-6176-4569-8292-d62fff4db545', 'mathematics', '2', 'Patterns and Relationships', '1.1', 'product', 'Group work', 'Copy and extend growing patterns.', 6, '2025-12-19T03:09:53.600637+00:00', '2025-12-19T03:09:53.600637+00:00'),
  ('2bbad7d1-f44e-4dc4-9d29-d9f6b0c830d2', 'mathematics', '2', 'Patterns and Relationships', '1.1', 'product', 'Group work', 'Recognize patterns as either repeating or growing. Present learners with a piece of fabric with a similar design as shown below. Learners will look at the illustration to identify the rule and add on to the repetition. Checklist Can identify shapes and rule (described in own words) Can accurately continue the pattern ) ) Retrieved from https://images.google.com/', 7, '2025-12-19T03:09:53.600637+00:00', '2025-12-19T03:09:53.600637+00:00'),
  ('7a5984f0-1a14-41a3-92c1-89952d81e950', 'mathematics', '2', 'Patterns and Relationships', '1.1', 'product', 'Group work', 'Can students demonstrate patterns through dancing, or performing actions? E.g. clap, stomp feet, click. Observation Have students listen to a sound pattern based on the following. Students will line up to continue the pattern by demonstrating the next correct action (term). Retrieved from https://images.google.com/', 8, '2025-12-19T03:09:53.600637+00:00', '2025-12-19T03:09:53.600637+00:00'),
  ('0527c69c-996a-4bd0-99e7-3989240daed6', 'mathematics', '2', 'Patterns and Relationships', '1.1', 'product', 'Group work', 'Provide opportunities for students to build, extend and describe patterns formed with letters, numbers and shapes. Retrieved from https://images.google.com/', 9, '2025-12-19T03:09:53.600637+00:00', '2025-12-19T03:09:53.600637+00:00'),
  ('6a57a754-ee3a-4823-aa8a-746c3548f2f0', 'mathematics', '2', 'Patterns and Relationships', '1.1', 'product', 'Group work', 'Provide opportunities for learners to create their pattern and explain the rule formed by these patterns. Grade 2 Mathematics Curriculum 85 Specific Curriculum Outcomes Inclusive Assessment Strategies Inclusive Learning Strategies Values:', 10, '2025-12-19T03:09:53.600637+00:00', '2025-12-19T03:09:53.600637+00:00'),
  ('9f9dff6d-c70c-42c9-a88e-2e15d9ade978', 'mathematics', '2', 'Patterns and Relationships', '1.1', 'product', 'Group work', 'Acknowledge patterns in their environment by identifying and describing the pattern observed around them.', 11, '2025-12-19T03:09:53.600637+00:00', '2025-12-19T03:09:53.600637+00:00'),
  ('4b14fcf1-46b1-44d2-acd4-06b5c2b5675b', 'mathematics', '2', 'Patterns and Relationships', '1.1', 'product', 'Group work', 'Identify and enjoy patterns in poems, stories, (folk and modern) within their culture. Student can describe pattern Student demonstrates next term in pattern (e.g. two claps, a snap and a tap) Retrieved from https://images.google.com/', 12, '2025-12-19T03:09:53.600637+00:00', '2025-12-19T03:09:53.600637+00:00'),
  ('ad77bbfd-da33-4398-9ac6-6a92f7846ccf', 'mathematics', '2', 'Patterns and Relationships', '1.1', 'product', 'Group work', 'Are students able to describe patterns given and patterns formed? E.g. 1, 2, 3, 4, 5, ___, ____ Concrete', 13, '2025-12-19T03:09:53.600637+00:00', '2025-12-19T03:09:53.600637+00:00'),
  ('470e57a4-aa9d-4638-9053-b27aee0f3b20', 'language-arts', '1', 'Listening and Speaking', '1', 'observation', 'General', 'to transition between subjects', 1, '2025-12-19T18:27:18.991232+00:00', '2025-12-19T18:27:18.991232+00:00'),
  ('9e2f2f75-d9e3-4623-be7c-8e23b8efc55b', 'language-arts', '1', 'Listening and Speaking', '1', 'observation', 'General', 'to provide a short o pportunity to stretch and/or relax', 2, '2025-12-19T18:27:18.991232+00:00', '2025-12-19T18:27:18.991232+00:00'),
  ('1243956b-c5d7-425d-8181-25f94e9d998e', 'language-arts', '1', 'Listening and Speaking', '1', 'observation', 'General', 'to connect a well know song to the lesson''s focus After the listening experience, engage the class or small groups of learners about:', 3, '2025-12-19T18:27:18.991232+00:00', '2025-12-19T18:27:18.991232+00:00'),
  ('b33fe09a-f261-40cf-ae0c-e857776151af', 'language-arts', '1', 'Listening and Speaking', '1', 'observation', 'General', 'was the selection enjoyable and why?', 4, '2025-12-19T18:27:18.991232+00:00', '2025-12-19T18:27:18.991232+00:00'),
  ('35e0488a-555b-4058-b7cc-d0bfc082ef9e', 'language-arts', '1', 'Listening and Speaking', '1', 'observation', 'General', 'how did the selection make them feel?', 5, '2025-12-19T18:27:18.991232+00:00', '2025-12-19T18:27:18.991232+00:00'),
  ('49cfff2a-216e-4dc6-8ea2-11a172305da0', 'language-arts', '1', 'Listening and Speaking', '1', 'observation', 'General', 'what was a s pecial part of the selection they would like to share?', 6, '2025-12-19T18:27:18.991232+00:00', '2025-12-19T18:27:18.991232+00:00'),
  ('fecc8278-b95c-4911-bf2a-e0e505cd8f08', 'language-arts', '1', 'Listening and Speaking', '1', 'observation', 'General', 'what other songs, stories, etc. would they enjoy listening to? As learners respond, make note of their participation, language choice, vocabulary use, sentence use, etc. The Sounds of Silence (SCO 1. 2): Gather learners together and demonstrate how to pause and listen by asking the learners to create total silence in the classroom. Once learners are silent, direct their attention to the remaining ambient or "non voice" sounds . As a sound is identified , engage the class in a "whisper" conversation to discuss the messages and meaning each sound convey s. For example:', 7, '2025-12-19T18:27:18.991232+00:00', '2025-12-19T18:27:18.991232+00:00'),
  ('0006a8a6-5650-46d6-b215-25317703c941', 'language-arts', '1', 'Listening and Speaking', '1', 'observation', 'General', 'truck passing by – where do you', 8, '2025-12-19T18:27:18.991232+00:00', '2025-12-19T18:27:18.991232+00:00'),
  ('e0fff1f9-e811-4e7a-8c3c-f1fae7bf64bc', 'language-arts', '1', 'Writing and Representing', '5', 'product', 'Group work', 'As each Treasure H unt unfolds, the teacher observes, asks questions and provides feedback.', 1, '2025-12-19T18:27:18.991232+00:00', '2025-12-19T18:27:18.991232+00:00'),
  ('26351979-d869-43b2-9cca-b3afbc6a7892', 'language-arts', '1', 'Writing and Representing', '5', 'product', 'Group work', 'How do you know this is a list?', 2, '2025-12-19T18:27:18.991232+00:00', '2025-12-19T18:27:18.991232+00:00'),
  ('75b5ba71-a20e-463b-8f10-953046528cf6', 'language-arts', '1', 'Writing and Representing', '5', 'product', 'Group work', 'Why is this list important?', 3, '2025-12-19T18:27:18.991232+00:00', '2025-12-19T18:27:18.991232+00:00'),
  ('025aeb67-bd57-4096-8c60-2fcaba31073a', 'language-arts', '1', 'Writing and Representing', '5', 'product', 'Group work', 'How do you know this is a story? Who do you', 4, '2025-12-19T18:27:18.991232+00:00', '2025-12-19T18:27:18.991232+00:00'),
