  ('426b71a7-f534-403a-8fe6-d25af2570a88', 'mathematics', '1', 'Geometrical Thinking', '1.1', 'game-based', 'Website Resources', 'Game websites: splashlearn.com/math/shapes-games-for-1st-graders, abcya.com/games/shapes_geometry_game, education.com/games/first-grade/geometry/, smashmaths.com.au/measurement-and-geometry/location-and-transformation/flip-slide-and-turn', 37, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('e615149e-d511-4060-a742-70d8bcc89b2a', 'mathematics', '1', 'Geometrical Thinking', '1.2', 'game-based', 'Musical Chairs', 'Play Musical Chairs and Old Grady on shapes so students'' ability to identify and name shapes is highlighted', 1, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('510e9a81-bff4-4139-80b2-5fcf4170e0e4', 'mathematics', '1', 'Geometrical Thinking', '1.2', 'game-based', 'Mystery Bag', 'Mystery Bag of Shapes: Students are blindfolded, choose a shape from the mystery bag, then give a description of the chosen shape', 2, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('64d7cb8d-8969-4b25-8d10-97fe2606afcd', 'mathematics', '1', 'Geometrical Thinking', '1.2', 'product', 'Drawing', 'Allow students to draw 2D and 3D shapes', 3, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('0e6693ba-ca1a-4327-bdee-2bb9df38931b', 'mathematics', '1', 'Geometrical Thinking', '1.2', 'product', 'Poster Creation', 'Create a poster on their favorite shape and its properties', 4, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('5d516f5f-8bd8-4d10-a294-ccf9b9427d54', 'mathematics', '1', 'Geometrical Thinking', '1.2', 'product', 'Poster Creation', 'Create a poster to advertise their favourite shape and its properties', 5, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('5de755f2-3e9c-4196-8f57-c16f7527b0b5', 'mathematics', '1', 'Geometrical Thinking', '1.2', 'product', 'Compound Shapes', 'Use one or more shapes to construct a compound shape. Draw a shape using a variety of plane shapes', 6, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('b2e0a987-24fc-4dfa-965f-f6fd0056e426', 'mathematics', '1', 'Geometrical Thinking', '1.2', 'project', 'Shape Creation', 'Allow students to create both 2D and 3D shapes using local materials', 7, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('4eef6904-f15a-4600-8e66-1dc290bf0ae8', 'mathematics', '1', 'Geometrical Thinking', '1.2', 'project', 'Shape Book', 'Create a shape book which highlights the shapes and their properties', 8, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('1b933a49-d797-4518-8be0-f9c50fb9a3ff', 'mathematics', '1', 'Geometrical Thinking', '1.2', 'project', 'Collage', 'Students make a collage with different shapes and materials', 9, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('1cda9167-3b4e-495a-82a3-4e3e5415ae52', 'mathematics', '1', 'Geometrical Thinking', '1.2', 'differentiated', 'General', 'Differentiate based on students'' individual needs and abilities. Provide additional support or scaffolding for students who struggle with vocabulary. Offer extension activities for those who demonstrate proficiency', 10, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('e9551c2c-c043-4a2b-8134-5701b255378c', 'mathematics', '1', 'Geometrical Thinking', '1.2', 'differentiated', 'Tier 1', 'Tier 1: Justify the shape appropriateness for its usage in real life context', 11, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('0f839b8d-4ca3-4ae4-a974-fa1ee2a80aa1', 'mathematics', '1', 'Geometrical Thinking', '1.2', 'differentiated', 'Tier 2', 'Tier 2: State the properties of all shapes', 12, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('e5cb4afc-cc7e-45f6-a99e-4ec7a5586047', 'mathematics', '1', 'Geometrical Thinking', '1.2', 'differentiated', 'Tier 3', 'Tier 3: Classify the given shapes based on the identified attributes', 13, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00');
INSERT INTO curriculum_assessment_strategies (id, subject, grade_level, strand, elo_number, strategy_type, strategy_category, description, sort_order, created_at, updated_at) VALUES
  ('cccbb9bb-cf8e-4db6-a9f1-50c22be7f4b2', 'mathematics', '1', 'Geometrical Thinking', '1.2', 'performance', 'Mystery Object', 'Pupils create a mystery object using 2D shapes and 3D objects and make oral presentations', 14, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('9ee36f23-6d44-4e06-8062-37eb743262ef', 'mathematics', '1', 'Geometrical Thinking', '1.2', 'performance', 'Show and Tell', 'Allow students to do show and tell on a selected shape (name the shape, properties, importance and objects it can be seen)', 15, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('855f3bfd-1132-4726-915d-9d6249a70118', 'mathematics', '1', 'Geometrical Thinking', '1.2', 'checklist', '3D Construction', 'Observe students as they construct 3D shapes', 16, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('6ec5e126-c5c5-4ebd-813e-05f68b486174', 'mathematics', '1', 'Geometrical Thinking', '1.2', 'checklist', 'Sorting', 'Observe students as they sort and group shapes according to the number of sides, corners and faces', 17, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('ac210dab-25ab-408d-ad13-d2add5a8eebd', 'mathematics', '1', 'Geometrical Thinking', '1.2', 'investigation', 'General', 'Provide students with a collection of 3D objects (cube, cone, sphere, cylinder). Ask them to investigate and identify different characteristics of each object (number of faces, edges, corners). Have them draw and label each object in their learning log', 18, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('976a81a4-2f27-41ce-a077-3534e6f7136e', 'mathematics', '1', 'Geometrical Thinking', '1.2', 'exhibition', 'General', 'Select a 2D or 3D shape, and students should carry from home objects that reveal their shape', 19, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('9597db27-b2ac-4615-8324-4632de941669', 'mathematics', '1', 'Geometrical Thinking', '1.2', 'exhibition', 'Material Selection', 'Provide students and allow students to select the most appropriate material and construct 3D shapes', 20, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('23378507-df2b-481f-a832-da8f4683b11a', 'mathematics', '1', 'Geometrical Thinking', '1.2', 'rubric', 'Oral Presentations', 'Use rubric to assess students'' oral presentations, projects, how they present their shapes in their booths, videos created that depict the properties of shapes', 21, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('6c9e0e5a-73ae-4fd9-9a5a-0a7a4d3a2156', 'mathematics', '1', 'Geometrical Thinking', '1.2', 'rubric', 'Oral Presentations', 'Rubric criteria: Student speaks clearly and loudly enough to be heard by the class (Always/Sometimes/Rarely)', 22, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('ed8f96ed-9825-42dd-a871-f12f1eac6921', 'mathematics', '1', 'Geometrical Thinking', '1.2', 'rubric', 'Oral Presentations', 'Rubric criteria: Student describes their 3D object using descriptive language (e.g. size, shape, color, texture, face)', 23, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('ce3a2057-2f6c-441b-8e1b-c8ba1e479e78', 'mathematics', '1', 'Geometrical Thinking', '1.2', 'rubric', 'Oral Presentations', 'Rubric criteria: Student shares an interesting fact or story about their 3D object', 24, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('40156d0a-023d-41e2-84fd-e416ded00831', 'mathematics', '1', 'Geometrical Thinking', '1.2', 'rubric', 'Oral Presentations', 'Rubric criteria: Student shows confidence and enthusiasm while presenting', 25, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('81bc8f16-e3e2-4f2b-af61-996efecd8241', 'mathematics', '1', 'Geometrical Thinking', '1.2', 'journal', 'General', 'Write about a shape they observe on their way to school', 26, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('72b07281-cd0d-4b1f-bd9f-bf7960b389a1', 'mathematics', '1', 'Geometrical Thinking', '1.2', 'learning-log', 'General', 'Have students write about what they are learning and how they feel about it: "Today I am learning about______________" "I like it because_____________"', 27, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('846fca9b-3715-4180-a13c-5c0dd6a6a10c', 'mathematics', '1', 'Geometrical Thinking', '1.2', 'learning-log', 'Shape Log', 'Pupils create a shape log which records the different shapes that they observe in their environment for a given period', 28, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('1ceb012c-5e9c-48c4-b4ea-ff647538136b', 'mathematics', '1', 'Geometrical Thinking', '1.2', 'worksheet', 'Matching', 'Provide a list of 2D and 3D shapes and students are required to match them with their corresponding names or representations', 29, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('694c3e56-2d09-4caa-a569-3b99104a1cd5', 'mathematics', '1', 'Geometrical Thinking', '1.2', 'exit-ticket', 'General', 'Use exit tickets which require students to identify the shape shown', 30, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('1fa92ddc-761c-45f2-bd59-3bb261e8547d', 'mathematics', '1', 'Geometrical Thinking', '1.2', 'worksheet', 'Colouring', 'Provide worksheets whereby students are required to colour each shape using a specific color code', 31, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('637962e1-afec-487b-ac33-bb9b82dbcdeb', 'mathematics', '1', 'Geometrical Thinking', '1.2', 'written-response', 'General', 'Use written responses such as short answer questions or journal prompts to assess students'' ability to compare the characteristics of shapes and objects', 32, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('5e387812-7a17-4a9d-8a85-b9c3e0d06ed4', 'mathematics', '1', 'Geometrical Thinking', '2.1', 'digital', 'Virtual Manipulatives', 'Use virtual manipulatives or interactive simulations to allow students to identify and name plane and solid shapes. Assess using a rubric', 1, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('4be3d151-6d34-4017-aaed-f66d60c5665e', 'mathematics', '1', 'Geometrical Thinking', '2.1', 'picture-based', 'General', 'Use pictures or diagrams of everyday objects that resemble cubes, cones, cylinders, and spheres. Ask students to identify and name the 2D shapes within them', 2, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('74ee3ce1-510f-4ca3-a517-a77c9344e1a3', 'mathematics', '1', 'Geometrical Thinking', '2.1', 'picture-based', 'Digital Platform', 'Can be done through worksheets or digital platforms where students can drag and drop labels to match the shapes they see in the pictures', 3, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('686d9e77-e0a8-4f43-b3b2-d46f67a45cfb', 'mathematics', '1', 'Geometrical Thinking', '2.1', 'checklist', 'Shape Manipulation', 'Use a checklist to observe students as they manipulate 2D shapes and 3D objects to describe attributes and characteristics (number of corners, sides - flat or curved)', 4, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('abec0e0b-b322-4406-ab53-3cc57d75781d', 'mathematics', '1', 'Geometrical Thinking', '2.1', 'questioning', 'General', 'Example question: "Which shape has six (6) square faces and eight (8) corners?"', 5, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('962faaad-042f-4d13-94dd-350854d381d3', 'mathematics', '1', 'Geometrical Thinking', '2.1', 'worksheet', 'Differentiation', 'Provide students with written assignments with shapes of different size, colour and orientation that require students to differentiate shapes', 6, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('cb4b401c-d50b-4db7-b7db-49f59f3a450e', 'mathematics', '1', 'Geometrical Thinking', '2.1', 'worksheet', 'Colouring', 'Worksheets that require students to colour each shape using a colour code', 7, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('bdc4cff3-d6e9-4eda-8337-119bbc88a55f', 'mathematics', '1', 'Geometrical Thinking', '2.1', 'worksheet', 'Matching', 'Allow students to match the shapes that are the same', 8, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('d4ba01e2-3d57-48ea-84ea-8437eade27d1', 'mathematics', '1', 'Geometrical Thinking', '2.1', 'worksheet', 'Shape Identification', 'Identify each shape drawn and use a colour code to colour each shape', 9, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('25901c86-3ae0-4477-a3ce-f816fbaf5452', 'mathematics', '1', 'Geometrical Thinking', '2.1', 'worksheet', 'Writing', 'Write a sentence about each shape (e.g., "The square is blue.")', 10, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('4cc9b9b8-3de4-48e8-9d33-da376f603fee', 'mathematics', '1', 'Geometrical Thinking', '2.1', 'product', 'Descriptive Drawing', 'Provide students with opportunities to create drawings or diagrams of cubes, cones, cylinders, and spheres. Label the features using appropriate vocabulary', 11, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('bf28c449-7bc6-4251-ab00-10ea49e4a9ac', 'mathematics', '1', 'Geometrical Thinking', '2.1', 'observation', 'Vocabulary Use', 'Encourage students to identify and describe the features using appropriate vocabulary. Observe their ability to use the correct language', 12, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('97c7956d-64d9-4797-b1a6-270478911014', 'mathematics', '1', 'Geometrical Thinking', '2.1', 'project', 'Shape Design', 'Students design their own shape using local materials and writing its attributes. Assess projects using a rubric', 13, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('68479992-a1ad-46a0-a874-3275158542cb', 'mathematics', '1', 'Geometrical Thinking', '2.1', 'performance', 'Building Tasks', 'Design performance tasks to be assessed using a rubric such as building a specific 3D shape or drawing a 2D shape with a certain number of sides or corners', 14, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('c1b6d7c0-c463-49c5-959e-5acbe5c78273', 'mathematics', '1', 'Geometrical Thinking', '2.1', 'product', 'Shape Book', 'Creation of a shape book', 15, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('5b4cffc8-23e0-4d11-99cc-ca3643112abb', 'mathematics', '1', 'Geometrical Thinking', '2.1', 'product', 'Collaborative Poster', 'Have students work collaboratively to create a shape poster', 16, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('f319d787-5e19-4da8-b658-79ba7bda1bc1', 'mathematics', '1', 'Geometrical Thinking', '2.1', 'product', 'Collage', 'Have students work collaboratively to create a collage of shapes made from different materials', 17, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('ce06b213-50c4-4683-afe1-542408c708a2', 'mathematics', '1', 'Geometrical Thinking', '2.1', 'digital', 'Online Quizzes', 'Use online formative assessment tools that provide instant feedback. Online quizzes or interactive assessments with images of 2D and 3D shapes', 18, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('defe0e63-e3ab-4cf2-a025-a4fa3adc86c5', 'mathematics', '1', 'Geometrical Thinking', '2.1', 'digital', 'Interactive Assessment', 'Students select the correct 2D shapes or draw on the images to highlight the shapes they identify', 19, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('4c538129-e26b-4e85-9972-723cc9acb1ab', 'mathematics', '1', 'Geometrical Thinking', '2.1', 'discussion', 'General', 'Foster a collaborative learning environment where students share their observations and ideas. Encourage students to explain their reasoning and use appropriate vocabulary (edges, vertices, sides, circles, triangles)', 20, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('4d9b8c3d-3a71-4b6b-97c7-47a1a5ede370', 'mathematics', '1', 'Geometrical Thinking', '2.1', 'verbal', 'General', 'Students are given the opportunity to describe the attributes and characteristics of 2D shapes and 3D objects. Assess using a rubric', 21, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('8548db56-2dd2-4ea8-aff2-7c07aa59ac37', 'mathematics', '1', 'Geometrical Thinking', '2.1', 'digital', 'Drawing Tools', 'Students use digital drawing tools to create their own representations of 2D shapes and 3D shapes. Assess using a checklist. Sites: tuxpaint.org, sketch.io/sketchpad, google.com/intl/en_in/drive/apps.html', 22, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('ea6bde07-1f7a-4bd7-8be4-b801444380a8', 'mathematics', '1', 'Geometrical Thinking', '2.1', 'observation', 'Real-World Objects', 'Provide a variety of real-world objects for students to describe solid shapes. Ask students to identify and name the 2D shapes they can find in given solid shapes', 23, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('50d8a088-3594-4ce2-880b-48f9c69e6c9d', 'mathematics', '1', 'Geometrical Thinking', '2.1', 'observation', 'Real-World Objects', 'Example: a soccer ball can be used to identify a circle (for the patches) and a sphere (for the overall shape)', 24, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('4adbdc7e-9671-4825-9a47-1e0784269089', 'mathematics', '1', 'Geometrical Thinking', '2.1', 'observation', 'Transformations', 'Monitor students and provide feedback on pupils'' ability to transform geometric shapes', 25, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('b8076a9c-5314-46c2-a221-676b63b2b90d', 'mathematics', '1', 'Geometrical Thinking', '2.2', 'game-based', 'Shape Hunt', 'Take students on a shape hunt around the classroom or school. Give them a list of 2D and 3D shapes to find (circles, squares, triangles, rectangles, spheres, cubes, cylinders). Have them identify and name each shape they find', 1, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('7811169c-aaec-41dd-befd-b9e5f8b5fe77', 'mathematics', '1', 'Geometrical Thinking', '2.2', 'questioning', '2D Shapes', 'Ask open-ended questions that prompt students to identify and name 2D shapes. Example: "Can you point to the shape that has four sides of equal length and four right angles?"', 2, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('49a85af9-23e2-40ea-b866-d322b9d43662', 'mathematics', '1', 'Geometrical Thinking', '2.2', 'questioning', '2D Shapes', 'Example question: "What is the name of the shape that has one curved side and no corners?"', 3, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('9d21de81-05a3-4956-8204-8664b37b6e02', 'mathematics', '1', 'Geometrical Thinking', '2.2', 'questioning', '3D Objects', 'Ask open-ended questions that prompt students to identify and name 3D objects. Example: "What is the name of the object that has a round base and a pointed top?"', 4, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('3aabd183-703a-4984-a6af-d87877b4cd66', 'mathematics', '1', 'Geometrical Thinking', '2.2', 'questioning', '3D Objects', 'Example question: "Can you name the object that has six square faces?"', 5, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('ececb519-22dd-4a29-b64b-5bccfb7f1245', 'mathematics', '1', 'Geometrical Thinking', '2.2', 'game-based', 'Shape Games', 'Use games that involve identifying and naming 2D or 3D shapes: Shape memory, Shape bingo. These games make assessment more fun and engaging while allowing observation of skills', 6, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00');
INSERT INTO curriculum_assessment_strategies (id, subject, grade_level, strand, elo_number, strategy_type, strategy_category, description, sort_order, created_at, updated_at) VALUES
  ('86399b55-729f-4e82-9bc4-9825dd125ae3', 'mathematics', '1', 'Geometrical Thinking', '2.2', 'observation', 'Sorting Activities', 'Observe students as they participate in group activities or independent work that involve sorting 2D shapes and 3D objects based on their attributes. Take note of their ability to identify and sort objects correctly', 7, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('0f294126-5847-49e4-9969-15907fcdcf12', 'mathematics', '1', 'Geometrical Thinking', '2.2', 'questioning', 'Sorting', 'Ask open-ended questions that prompt students to sort 2D shapes and 3D objects based on their attributes. Example: "Can you sort these shapes based on the number of sides?"', 8, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('a697f58d-c511-4d71-ae90-39c5841bd895', 'mathematics', '1', 'Geometrical Thinking', '2.2', 'questioning', 'Sorting', 'Example question: "How would you sort these objects based on the number of vertices?"', 9, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('567fbfee-e545-46d3-a626-9e2698e6fc93', 'mathematics', '1', 'Geometrical Thinking', '2.2', 'observation', 'Hands-On Sorting', 'Provide students with hands-on activities such as manipulatives or shape and object models that require them to sort based on attributes. Observe their ability to use the materials to correctly sort objects', 10, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('4455f382-b79d-4e52-a29b-6d613d5cf873', 'mathematics', '1', 'Geometrical Thinking', '2.2', 'game-based', 'Attribute Games', 'Use games that involve sorting 2D shapes and 3D objects based on their attributes: Attribute matching, Attribute bingo', 11, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('fe51e865-3882-4cfc-9232-73a887e27f9b', 'mathematics', '1', 'Geometrical Thinking', '2.2', 'graphic-organizer', 'Venn Diagram', 'Draw two overlapping circles on the board, one labeled "2D Shapes" and the other labeled "3D Objects". Ask students to name different shapes and objects and place them in the appropriate circle based on their dimensions. Encourage them to explain why they placed the shape or object in that circle', 12, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('5436c4e7-c9d6-44db-8648-537587272e47', 'mathematics', '1', 'Geometrical Thinking', '2.2', 'performance', 'Sorting Task', 'Provide students with a set of pictures of 2D shapes and 3D objects. Ask them to sort them into two categories based on their dimensions. Can be done individually or in small groups', 13, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('a45940e9-bddf-4bf8-9600-04128cacf375', 'mathematics', '1', 'Geometrical Thinking', '2.2', 'observation', 'Documentation', 'Observe students as they work and take notes on their progress. Identify areas where students may need additional support or guidance', 14, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('b26d6129-fb39-43dd-822a-b006fb4aa111', 'mathematics', '1', 'Geometrical Thinking', '2.2', 'differentiated', 'Learning Styles', 'Provide different options for creating shapes and objects (drawing, sculpting, building with blocks). Help students with different learning styles demonstrate their understanding', 15, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('c1960fe3-552b-45a2-895a-a37c56446f4d', 'mathematics', '1', 'Geometrical Thinking', '2.2', 'observation', 'Real-World Hands-On', 'Provide hands-on activities like building with blocks or playing with 3D shapes. Observe their interactions with the objects and listen to their verbal descriptions to assess their understanding', 16, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('cd2e9c35-f270-4534-b3c9-553d2c1a119d', 'mathematics', '1', 'Geometrical Thinking', '2.2', 'verbal', 'Real-World Objects', 'Engage students in conversation about real-world objects. Ask them to describe a familiar object or use open-ended questions to prompt discussion about the properties of shapes and objects', 17, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('1fca4967-937e-4144-9574-9992532bb55f', 'mathematics', '1', 'Geometrical Thinking', '2.2', 'game-based', 'Scavenger Hunt', 'Games and activities like scavenger hunts or sorting games. Example: Ask students to find objects around the classroom that are a certain shape', 18, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('6ec70a27-d89a-4e78-89bd-e3a820b31335', 'mathematics', '1', 'Geometrical Thinking', '2.2', 'game-based', 'Sorting Game', 'Example: Ask students to sort objects by shape', 19, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('82e29afd-6364-49cd-b401-0ad93c459ce4', 'mathematics', '1', 'Geometrical Thinking', '2.3', 'questioning', 'General', 'Ask students questions about shapes, objects, and how they are related to assess their understanding', 1, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('b3643fe5-e681-4119-bdeb-a2155099f79d', 'mathematics', '1', 'Geometrical Thinking', '2.3', 'verbal', 'Description', 'Ask students to describe the shapes they see, using their own words. Allows them to use creativity and build confidence in verbal expression', 2, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('f648d811-1af3-409e-8cfe-231201665fb6', 'mathematics', '1', 'Geometrical Thinking', '2.3', 'verbal', 'Manipulatives', 'Ask students to use manipulatives such as blocks and playdough to create geometric shapes and describe them', 3, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('2cda6002-b9f6-4beb-ad39-7adf1e4f7385', 'mathematics', '1', 'Geometrical Thinking', '2.3', 'visual', 'Pictures/Diagrams', 'Use pictures and diagrams to help students identify different shapes. Show real-life objects and ask them to identify shapes within them', 4, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('6103e667-4bbd-44b8-97a3-87568ec2e0c5', 'mathematics', '1', 'Geometrical Thinking', '2.3', 'visual', 'Flashcards', 'Use flashcards with shapes printed on them', 5, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('5828e45f-51e3-4820-b151-59fb291304f2', 'mathematics', '1', 'Geometrical Thinking', '2.3', 'collaborative', 'General', 'Encourage students to work together in small groups to identify and describe shapes. Allows for peer-to-peer learning. Gives students opportunity to practice communication and social skills', 6, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('80a6c785-a6c9-42aa-9fc1-7a7b2af377c1', 'mathematics', '1', 'Geometrical Thinking', '2.3', 'differentiated', 'Individualized', 'Provide students with individualized learning plans that cater to their specific needs. Some students may benefit from visual aids while others may need more hands-on activities', 7, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('2a165e61-96e7-4b01-b655-5a92b04d16ac', 'mathematics', '1', 'Geometrical Thinking', '2.3', 'game-based', 'Bingo/Memory', 'Use games such as shape bingo or memory matching games. Makes learning more engaging and fun for students', 8, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('3c24d107-0af6-462c-ab0d-b28dcb8cc27b', 'mathematics', '1', 'Geometrical Thinking', '2.3', 'observation', 'Interaction', 'Observe students on task as they interact with different geometric shapes', 9, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('cfcd661e-e405-4c70-a173-7fce661ada4d', 'mathematics', '1', 'Geometrical Thinking', '2.3', 'observation', 'Categorizing', 'Observe students as they categorize geometric shapes according to their attributes', 10, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('3e6cd08a-8475-4224-a779-3c40ca229587', 'mathematics', '1', 'Geometrical Thinking', '2.3', 'performance', 'Shape Sort', 'Materials: Various 2D and 3D shapes (circle, square, triangle, rectangle, cube, cylinder, sphere, cone) and a large sheet of paper with two sections labeled "2D shapes" and "3D shapes"', 11, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('9fb91117-a23c-47bd-8241-33b25c320502', 'mathematics', '1', 'Geometrical Thinking', '2.3', 'performance', 'Shape Sort', 'Instructions: Show students the different 2D and 3D shapes and ask them to name each one. Explain that they will be sorting the shapes into two categories', 12, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('42addd1d-848c-4144-8769-fc4cacf5d3d1', 'mathematics', '1', 'Geometrical Thinking', '2.3', 'performance', 'Shape Sort', 'Demonstrate how to sort by placing a circle, square, triangle, and rectangle in the "2D shapes" section, and a cube, cylinder, sphere, and cone in the "3D shapes" section', 13, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('1b1c02b8-f833-4c4c-94b7-00b8274b1fa3', 'mathematics', '1', 'Geometrical Thinking', '2.3', 'performance', 'Shape Sort', 'Have students take turns sorting shapes into the correct section. Use a timer to make it more engaging and challenging', 14, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('5ce16139-8d6f-4f60-8fc5-e1e8cb95157e', 'mathematics', '1', 'Geometrical Thinking', '2.3', 'performance', 'Shape Sort', 'Assessment: Observe students as they sort and note any difficulties. Ask students to explain why they sorted certain shapes into a particular category', 15, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('44e82195-9949-4f51-86e2-0d6f276c463b', 'mathematics', '1', 'Geometrical Thinking', '1.1', 'diagnostic', 'Shape Identification', 'Diagnostic question: Can students identify shapes in real-world objects?', 38, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('aa6ddf02-77db-4e97-939e-e17b5d240923', 'mathematics', '1', 'Geometrical Thinking', '1.1', 'diagnostic', 'Shape Naming', 'Diagnostic question: Can students name shapes correctly?', 39, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('78444f54-f7b8-4b5c-81f3-a5cc42282a1e', 'mathematics', '1', 'Geometrical Thinking', '1.1', 'diagnostic', 'Shape Characteristics', 'Diagnostic question: Can students identify characteristics of each shape?', 40, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('f0172eff-304d-41be-88c4-45bac0edc61d', 'mathematics', '1', 'Geometrical Thinking', '1.1', 'diagnostic', 'Different Perspectives', 'Diagnostic question: Can students identify shapes from different perspectives?', 41, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('ec2af183-bc4b-4ac8-9300-e2d9607c0495', 'mathematics', '1', 'Geometrical Thinking', '1.1', 'diagnostic', 'Positional Language', 'Diagnostic question: Can students use positional language correctly?', 42, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('f32f56e6-f45f-4489-92f5-42fc1fc41736', 'mathematics', '1', 'Geometrical Thinking', '1.1', 'diagnostic', 'Predictions', 'Diagnostic question: Can students make predictions about shape transformations?', 43, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('bf5b53d8-a27d-47d6-a000-0b98a3696bad', 'mathematics', '1', 'Geometrical Thinking', '1.2', 'diagnostic', 'Recognition', 'Diagnostic question: Can students recognize and name basic 2D shapes and 3D objects?', 33, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('3c2c7e3b-829c-4387-8183-6cd9941aeb14', 'mathematics', '1', 'Geometrical Thinking', '1.2', 'diagnostic', 'Construction', 'Diagnostic question: Can students construct shapes using appropriate materials?', 34, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('ede45aa5-e571-43fa-a38c-07d0392a33fe', 'mathematics', '1', 'Geometrical Thinking', '1.2', 'diagnostic', 'Justification', 'Diagnostic question: Can students justify properties of shapes?', 35, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('38df7c08-9a2f-42e8-a171-2620105620f5', 'mathematics', '1', 'Geometrical Thinking', '1.2', 'diagnostic', 'Composite Shapes', 'Diagnostic question: Can students replicate and construct composite shapes?', 36, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('7c3671d1-e0f2-4b79-a5d6-029cbf8da056', 'mathematics', '1', 'Geometrical Thinking', '1.2', 'diagnostic', 'Comparison', 'Diagnostic question: Can students compare characteristics of shapes?', 37, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('94711ba8-d36b-4e21-904e-d7492ec55a98', 'mathematics', '1', 'Geometrical Thinking', '1.2', 'diagnostic', 'Sorting/Patterning', 'Diagnostic question: Can students sort and pattern shapes based on characteristics?', 38, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('7ebd259a-627f-4a4b-ab51-193e8425599d', 'mathematics', '1', 'Geometrical Thinking', '2.1', 'diagnostic', '2D Attributes', 'Diagnostic question: Can students describe attributes of 2D shapes?', 26, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('e9c3c15e-2bd3-4780-b1dd-1b42b4d38b52', 'mathematics', '1', 'Geometrical Thinking', '2.1', 'diagnostic', '3D Attributes', 'Diagnostic question: Can students describe attributes of 3D objects?', 27, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('c503207d-dc93-4a80-833d-c4316f7355f8', 'mathematics', '1', 'Geometrical Thinking', '2.1', 'diagnostic', 'Compare/Contrast', 'Diagnostic question: Can students compare and contrast different shapes?', 28, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('f1b9890d-c060-40e2-a8c0-5bfe524fecfe', 'mathematics', '1', 'Geometrical Thinking', '2.1', 'diagnostic', 'Patterns', 'Diagnostic question: Can students create and extend patterns using shapes?', 29, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('11e11bba-ca17-4ac7-8ca3-a66f8e56c09a', 'mathematics', '1', 'Geometrical Thinking', '2.1', 'diagnostic', 'Vocabulary', 'Diagnostic question: Can students use appropriate vocabulary?', 30, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('00d70125-4dbc-4856-8e35-085e28b9e471', 'mathematics', '1', 'Geometrical Thinking', '2.2', 'diagnostic', '2D Identification', 'Diagnostic question: Can students identify and name 2D shapes?', 20, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('45bdec84-baa7-4c83-bb8c-18907629abb6', 'mathematics', '1', 'Geometrical Thinking', '2.2', 'diagnostic', '3D Identification', 'Diagnostic question: Can students identify and name 3D objects?', 21, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('3066bcac-b974-4c01-8600-fa94d41f47ec', 'mathematics', '1', 'Geometrical Thinking', '2.2', 'diagnostic', 'Sorting', 'Diagnostic question: Can students sort shapes based on attributes?', 22, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('db4aeeff-81a4-40b0-a906-e96983f186ca', 'mathematics', '1', 'Geometrical Thinking', '2.2', 'diagnostic', 'Compare 2D/3D', 'Diagnostic question: Can students compare and contrast 2D shapes and 3D objects?', 23, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('e7de4d5a-90a0-4ad6-8b7b-329e53970c21', 'mathematics', '1', 'Geometrical Thinking', '2.2', 'diagnostic', 'Creation', 'Diagnostic question: Can students create shapes using various materials?', 24, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00');
INSERT INTO curriculum_assessment_strategies (id, subject, grade_level, strand, elo_number, strategy_type, strategy_category, description, sort_order, created_at, updated_at) VALUES
  ('8b3b61d9-129b-4eb0-8683-155490125fc1', 'mathematics', '1', 'Geometrical Thinking', '2.2', 'diagnostic', 'Real-World', 'Diagnostic question: Can students identify real-world objects that are shapes?', 25, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('08dffe56-17e2-4a26-94f8-51f2caae0c66', 'mathematics', '1', 'Geometrical Thinking', '2.3', 'diagnostic', 'Basic Identification', 'Diagnostic question: Can students identify basic shapes?', 16, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('ebe75db9-c70c-41de-8d6c-f0ff4a47e929', 'mathematics', '1', 'Geometrical Thinking', '2.3', 'diagnostic', 'Material Creation', 'Diagnostic question: Can students create shapes with different materials?', 17, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('51f7e0ba-d013-4dbb-80f3-ee88c22818a7', 'mathematics', '1', 'Geometrical Thinking', '2.3', 'diagnostic', 'Environmental', 'Diagnostic question: Can students find shapes in the environment?', 18, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('6a86120f-ddef-4faa-9409-9e0f5c31cf5c', 'mathematics', '1', 'Geometrical Thinking', '2.3', 'diagnostic', 'Attribute Sorting', 'Diagnostic question: Can students sort shapes based on attributes?', 19, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('8544dc76-a5b5-43f2-9b87-892e88a979c9', 'mathematics', '1', 'Geometrical Thinking', '2.3', 'diagnostic', 'Pattern Creation', 'Diagnostic question: Can students create patterns using geometric shapes?', 20, '2026-01-06T12:02:06.526892+00:00', '2026-01-06T12:02:06.526892+00:00'),
  ('890f9ca8-4573-46d9-939a-2c34efaca341', 'mathematics', '1', 'Patterns and Relationships', '1.1', 'observation', 'Discussion', 'Teacher will observe by listening to students as they discuss the contents of the video and engage in reproducing the pattern embedded in the video', 1, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('0055739d-37b3-4381-bd80-410e2b00b0b0', 'mathematics', '1', 'Patterns and Relationships', '1.1', 'checklist', 'Pattern Recording', 'Use checklist to record identified behaviors during pattern activities', 2, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('b2bc9034-cd84-4649-9d90-b0c1a81118f8', 'mathematics', '1', 'Patterns and Relationships', '1.1', 'checklist', 'AB Patterns', 'Checklist criteria: Can call out the elements in the pattern in the order that they appear (left to right/right to left)', 3, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('7afbd75d-dc44-4f7b-a99e-ed28a009d57e', 'mathematics', '1', 'Patterns and Relationships', '1.1', 'checklist', 'AB Patterns', 'Checklist criteria: Can reproduce a pattern', 4, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('23c48373-9419-4b00-8650-471956296a29', 'mathematics', '1', 'Patterns and Relationships', '1.1', 'checklist', 'AB Patterns', 'Checklist criteria: Predict the missing elements in the pattern', 5, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('10a07357-13bd-4512-82bb-a884cc5d630c', 'mathematics', '1', 'Patterns and Relationships', '1.1', 'checklist', 'AB Patterns', 'Checklist criteria: Identify the pattern core at any point in the pattern', 6, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('daa90578-9f5e-4c44-b342-38617b053acc', 'mathematics', '1', 'Patterns and Relationships', '1.1', 'checklist', 'AB Patterns', 'Checklist criteria: Show the part that keeps repeating in the pattern', 7, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('6feca889-65d3-4320-b64f-17b0d61745bf', 'mathematics', '1', 'Patterns and Relationships', '1.1', 'checklist', 'AB Patterns', 'Checklist criteria: Describe a pattern', 8, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('b95a8521-020c-4027-9258-edac745432e8', 'mathematics', '1', 'Patterns and Relationships', '1.1', 'checklist', 'AB Patterns', 'Checklist criteria: Create a pattern', 9, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('abbc5ec0-f62b-432a-aade-d2d273eccbf8', 'mathematics', '1', 'Patterns and Relationships', '1.1', 'think-pair-share', 'Exploring Patterns', 'Observe learners as they construct their patterns. Ask questions at various cognitive levels to help learners conceptualize the characteristics of a repeating pattern', 10, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('bfd26990-f3b2-4e83-9a68-b6e4534219aa', 'mathematics', '1', 'Patterns and Relationships', '1.1', 'observation', 'Verbal Responses', 'Listen to learners as they respond to check for their conceptual understanding. Pay attention to their use of repeating pattern terminology', 11, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('f2662868-d3ad-4f71-b337-70cfe8364f5e', 'mathematics', '1', 'Patterns and Relationships', '1.1', 'checklist', 'Misconceptions', 'Use observational checklist to check and take note of misconceptions', 12, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('9f0e6fbb-c4e0-4d7a-b15b-73274e2e846d', 'mathematics', '1', 'Patterns and Relationships', '1.1', 'checklist', 'Pattern Creation', 'Checklist criteria: Selects own materials unassisted by teacher', 13, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('04744f61-13a6-4e73-b015-3f50f1a5e20e', 'mathematics', '1', 'Patterns and Relationships', '1.1', 'checklist', 'Pattern Creation', 'Checklist criteria: Selects a pattern format (ABABAB or ABCABCABC)', 14, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('0c71ab8d-8981-430d-ac7e-c66b9790c6a9', 'mathematics', '1', 'Patterns and Relationships', '1.1', 'checklist', 'Pattern Creation', 'Checklist criteria: Demonstrates an understanding of the pattern format with materials selected', 15, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('cf5c3abd-0630-4f90-af0e-a8a079616f0e', 'mathematics', '1', 'Patterns and Relationships', '1.1', 'checklist', 'Pattern Creation', 'Checklist criteria: Explains confidently the pattern using the correct terminology', 16, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('a1e44ca2-e885-4fbf-bc65-b1e3dbf8f965', 'mathematics', '1', 'Patterns and Relationships', '1.1', 'checklist', 'Pattern Creation', 'Checklist criteria: Worked cooperatively during the activity', 17, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('ee6904b2-dea8-4aba-8174-0590bc8b28f5', 'mathematics', '1', 'Patterns and Relationships', '1.1', 'checklist', 'Pattern Creation', 'Checklist criteria: Enjoyed the process in creating their product', 18, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('aaee15f5-08c7-4c92-8c66-0779cbffceac', 'mathematics', '1', 'Patterns and Relationships', '1.1', 'talking-circles', 'Pattern Translation', 'As students explore the patterns, change attributes and engage in translating them in circles, they will discuss their observations and share with each other', 19, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('8eadf4f4-59f7-4efe-9c6b-ea5ec448df8f', 'mathematics', '1', 'Patterns and Relationships', '1.1', 'observation', 'Pattern Translation', 'Teacher will observe and record student observable behaviours using an observation checklist', 20, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('cb27f4e3-ea39-4e6e-abb6-fc5de875dafe', 'mathematics', '1', 'Patterns and Relationships', '1.1', 'rubric', 'Pattern Translation', 'Rubric criteria: Learner can carry out the task for translating repeating patterns (Needs Intervention/Not yet approaching mastery/Approaching Mastery/Mastery)', 21, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('e3db0208-5e7a-471f-a2b0-354739910dce', 'mathematics', '1', 'Patterns and Relationships', '1.1', 'rubric', 'Pattern Translation', 'Rubric criteria - Needs Intervention: Carries out the task with assistance from the teacher', 22, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('3a64f328-9cb3-4872-b73d-10a739bc70a8', 'mathematics', '1', 'Patterns and Relationships', '1.1', 'rubric', 'Pattern Translation', 'Rubric criteria - Not yet approaching mastery: Carries out the task independently with 3 or more errors and/or omissions', 23, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('4262388e-7fb2-4482-ae74-1a5c10b9e2b9', 'mathematics', '1', 'Patterns and Relationships', '1.1', 'rubric', 'Pattern Translation', 'Rubric criteria - Approaching Mastery: Carries out the task independently with less than 3 errors and/or omissions', 24, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('78c3d93d-af5c-48be-8cc7-1c0e7817a70f', 'mathematics', '1', 'Patterns and Relationships', '1.1', 'rubric', 'Pattern Translation', 'Rubric criteria - Mastery: Carries out the task accurately', 25, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('42f61ded-d07a-43ae-b30e-a9d36219ee3d', 'mathematics', '1', 'Patterns and Relationships', '1.1', 'rubric', 'Pattern Translation', 'Rubric criteria: Correctly translates a repeating pattern with 2 to four element core from one form to another', 26, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('49088e48-fb41-4bb1-8d7a-e65f92efe8d8', 'mathematics', '1', 'Patterns and Relationships', '1.1', 'rubric', 'Pattern Translation', 'Rubric criteria: Describes/explains a pattern or pattern core/rule using the correct terminology for translating repeating patterns with 2 to 4-element cores', 27, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('32cebbd6-0d2b-47a9-968a-de9c2e937f75', 'mathematics', '1', 'Patterns and Relationships', '1.1', 'choral', 'Pattern Translation', 'Students will have a choral singing/chanting exercise where one group will begin singing or chanting the pattern and the other group will respond/translate', 28, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('a935cdbc-f719-43e8-a708-d381fc707664', 'mathematics', '1', 'Patterns and Relationships', '1.1', 'observation', 'Choral Response', 'Teacher will observe students'' chants to ensure that they have understood the translation of patterns. Use the checklist to assess the translation behavior demonstrated by the learner', 29, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('0cd03d4f-da9f-4eb6-8127-85134600d1b9', 'mathematics', '1', 'Patterns and Relationships', '1.1', 'think-pair-share', 'Error Analysis', 'Let learners put on their "Robocop hats" before they begin the activity. Ask probing questions to help learners think about the characteristics of a repeating pattern', 30, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('abb1b6db-5c06-4f8c-b8d1-654d4043c498', 'mathematics', '1', 'Patterns and Relationships', '1.1', 'think-pair-share', 'Error Analysis', 'In pairs, allow students to work on spotting and correcting errors in patterns presented in different contexts. Include patterns with no errors also', 31, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('73d79236-d157-4186-bceb-df2fa7bb6634', 'mathematics', '1', 'Patterns and Relationships', '1.1', 'discussion', 'Error Analysis', 'Give learners opportunities to share their discoveries', 32, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('bc784343-eed3-4413-8e2b-d16d51c829fd', 'mathematics', '1', 'Patterns and Relationships', '1.1', 'product', 'Border Creation', 'Students'' work will be assessed by the teacher using checklists to ensure that they use any of the pattern formats to create their designs using items found in and around the environment (ABABAB, ABCABCABC, AABAABAAB)', 33, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('ca94e4d2-ba3c-4d52-9960-daf9490fedc7', 'mathematics', '1', 'Patterns and Relationships', '1.1', 'product', 'Border Creation', 'OR create their borders using the 3 shapes given, using any of the formats. Use observation checklist to assess their products', 34, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('9e4299a6-3108-4207-9cca-d76e97def7b1', 'mathematics', '1', 'Patterns and Relationships', '1.1', 'worksheet', 'Task Cards', 'Allow learners to complete task cards to demonstrate their understanding of a repeating pattern', 35, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('2c2f93bf-d217-45ee-acfb-2f931bc339b5', 'mathematics', '1', 'Patterns and Relationships', '1.1', 'worksheet', 'Task Cards', 'Task card example: Put a check (√) on the T-shirt with a repeating pattern', 36, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('f1ab7ea3-aab2-4fa5-a71e-974a2c3525a3', 'mathematics', '1', 'Patterns and Relationships', '1.1', 'worksheet', 'Task Cards', 'Task card example: Circle the pattern core', 37, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('03b6165a-d256-4778-a412-a06163f44efb', 'mathematics', '1', 'Patterns and Relationships', '1.1', 'worksheet', 'Task Cards', 'Task card example: Copy the pattern', 38, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('a2d8c925-1eb9-41a9-a028-7e24ecab0282', 'mathematics', '1', 'Patterns and Relationships', '1.1', 'worksheet', 'Task Cards', 'Task card example: Circle the missing term in the pattern (multiple choice: a, b, c)', 39, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('6960fa1b-5636-4ad9-ab82-0b670ffeca24', 'mathematics', '1', 'Patterns and Relationships', '1.2', 'product', 'Role Play', 'Learners in pairs will discuss and create their own increasing pattern to reflect body movements and share with the class their creations', 1, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('0b79650c-435f-46f4-8b78-53c639c449c0', 'mathematics', '1', 'Patterns and Relationships', '1.2', 'observation', 'Role Play', 'Demonstration of the repeating pattern will be observed by the teacher and recorded for understanding using an observation chart', 2, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('8051e346-5696-4c79-a5c3-12114bb07af9', 'mathematics', '1', 'Patterns and Relationships', '1.2', 'checklist', 'Pattern Creation', 'Observation chart criteria: Created and demonstrated a repeating pattern using the ABBABBABB pattern (Yes/No/Needs Practice)', 3, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('1036dafa-f3e3-4c2b-837a-b57c0067ce66', 'mathematics', '1', 'Patterns and Relationships', '1.2', 'checklist', 'Pattern Creation', 'Observation chart criteria: Presented and explained their pattern thinking process, using content vocabulary such as next, pattern, after, etc.', 4, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('f1e47bf0-f8ad-4735-b5a3-157f1c2943f7', 'mathematics', '1', 'Patterns and Relationships', '1.2', 'checklist', 'Pattern Creation', 'Observation chart criteria: Had fun while engaging in the pattern creation process', 5, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00');
INSERT INTO curriculum_assessment_strategies (id, subject, grade_level, strand, elo_number, strategy_type, strategy_category, description, sort_order, created_at, updated_at) VALUES
  ('6afb1382-b06d-4267-b5ef-c3ad116c293e', 'mathematics', '1', 'Patterns and Relationships', '1.2', 'observation', 'Manipulatives', 'Engage learners in a discussion on what they are observing in the given sequence using coloured blocks and/or bottle caps', 6, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('512a98ec-c510-476c-9edc-019afb8b6130', 'mathematics', '1', 'Patterns and Relationships', '1.2', 'checklist', 'Observation Recording', 'Behaviours will be recorded using an observation checklist', 7, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('f413b542-d62f-4465-97be-e11bcd842f96', 'mathematics', '1', 'Patterns and Relationships', '1.2', 'think-pair-share', 'Pattern Creation', 'In pairs, students will then create a sequence of their own reflecting the ABABBABBB pattern and share with their peers', 8, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('8b864d7c-c177-4c62-b4e6-dc1d92987d2d', 'mathematics', '1', 'Patterns and Relationships', '1.2', 'observation', 'Progress Monitoring', 'Students'' progress will be monitored by the teacher as they engage in the activity', 9, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('8b6924e4-6136-46f3-9316-f8c4ab396d07', 'mathematics', '1', 'Patterns and Relationships', '1.2', 'checklist', 'Increasing Patterns', 'Checklist criteria: Can identify a pattern in a given sequence', 10, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('78af4969-52bc-41c3-bebc-73938399f2ae', 'mathematics', '1', 'Patterns and Relationships', '1.2', 'checklist', 'Increasing Patterns', 'Checklist criteria: Is able to explain the pattern in the demonstrated sequence', 11, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('15aad90b-f8bb-48a8-9033-31307780a1e9', 'mathematics', '1', 'Patterns and Relationships', '1.2', 'checklist', 'Increasing Patterns', 'Checklist criteria: Is able to extend the continuing pattern within the sequence with at least 2 to 3 elements', 12, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('29d3f7a9-b4dc-4724-adee-187d6174f806', 'mathematics', '1', 'Patterns and Relationships', '1.2', 'checklist', 'Increasing Patterns', 'Checklist criteria: Is able to explain their reason for selecting the continued pattern in the given sequence', 13, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('bd2e6fe3-6133-4d34-8c06-ed11af484c04', 'mathematics', '1', 'Patterns and Relationships', '1.2', 'checklist', 'Increasing Patterns', 'Checklist criteria: Uses appropriate vocabulary associated with patterns (next, after, beside, sequence, pattern)', 14, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('21184838-3ce4-4eed-9e8d-19cb7118d369', 'mathematics', '1', 'Patterns and Relationships', '1.2', 'checklist', 'Increasing Patterns', 'Checklist criteria: Able to create a sequence reflecting the pattern ABABBABBB in pairs', 15, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('49a249f9-0252-4ee4-b38c-d5c3d48f0f6e', 'mathematics', '1', 'Patterns and Relationships', '1.2', 'product', 'Story-Based', 'As the story is read, guiding questions will be asked based on patterns observed. Example: "How many buttons do you think will be on the third shirt, 4th shirt, 5th shirt?"', 16, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('684a57fa-7bdf-4ac1-b7bf-0a1c78e6e677', 'mathematics', '1', 'Patterns and Relationships', '1.2', 'observation', 'Vocabulary Use', 'Attention will be paid to the use of the vocabulary associated with increasing patterns (next, one more than, more)', 17, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('74dfb564-f65f-41dc-99c4-129ea8d919a2', 'mathematics', '1', 'Patterns and Relationships', '1.2', 'observation', 'Multiple Representations', 'Observable behaviours will be noted, such as students'' ability to reproduce the pattern using different modes of representations (play dough, blocks, drawings, or any manipulative)', 18, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('adbf0651-59d0-456c-bcfa-88190b7207a8', 'mathematics', '1', 'Patterns and Relationships', '1.2', 'self-assessment', 'Understanding Check', 'Students'' ability to demonstrate their understanding of an increasing or decreasing pattern using objects of their choice will be observed', 19, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('41bd69ac-de80-4196-bdfb-c8434c7015d4', 'mathematics', '1', 'Patterns and Relationships', '1.2', 'self-assessment', 'Feeling Check', 'Students will use a self-assessment to determine how they felt about completing the task: I''ve got it / I am struggling but learning / I need some help', 20, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('5552ec00-31a7-46d1-ae99-513d5e253fd9', 'mathematics', '1', 'Patterns and Relationships', '1.2', 'self-assessment', 'Error Analysis', 'Self-assessment checklist criteria: I can identify the pattern in the sequence', 21, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('0dc6becb-7559-4f81-8920-ff4730b53412', 'mathematics', '1', 'Patterns and Relationships', '1.2', 'self-assessment', 'Error Analysis', 'Self-assessment checklist criteria: I can spot the error and say what it is', 22, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('16a88ee5-6f37-40ec-b74d-8e51fde990f9', 'mathematics', '1', 'Patterns and Relationships', '1.2', 'self-assessment', 'Error Analysis', 'Self-assessment checklist criteria: I can fix the error', 23, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('61fb91b1-3a3e-43d5-9cd6-1bd81dc6611e', 'mathematics', '1', 'Patterns and Relationships', '1.2', 'self-assessment', 'Error Analysis', 'Self-assessment checklist criteria: I can extend the sequence', 24, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('a2caea7f-00a9-4ea4-828a-a6a44db3e409', 'mathematics', '1', 'Patterns and Relationships', '2.1', 'observation', 'Concrete Materials', 'Observe and check whether learners are able to represent unknown quantities from stories or situations, using concrete materials', 1, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('f6aa5ac3-abc9-45a1-b42b-12601b8359e8', 'mathematics', '1', 'Patterns and Relationships', '2.1', 'observation', 'Material Use', 'Make observations about the math material that the learners use to show the unknown quantities', 2, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('7f5f102b-a955-474f-a1a8-b895dc27105a', 'mathematics', '1', 'Patterns and Relationships', '2.1', 'checklist', 'Unknown Quantities', 'Checklist criteria: Can the learner write a number sentence to represent unknown quantities? (e.g., 1+ ___ = 4)', 3, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('6511dc19-d3c5-484d-bdfa-8cb455781e77', 'mathematics', '1', 'Patterns and Relationships', '2.1', 'checklist', 'Unknown Quantities', 'Checklist criteria: Can the learner represent unknown values using concrete materials and drawings?', 4, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('154deef5-f957-46f6-a872-a45619c0a6ce', 'mathematics', '1', 'Patterns and Relationships', '2.1', 'checklist', 'Unknown Quantities', 'Checklist criteria: Can the learner use part-part-whole relationship to represent unknown quantities?', 5, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('8bdf2ec2-de91-4daa-9018-689d86c18031', 'mathematics', '1', 'Patterns and Relationships', '2.1', 'checklist', 'Unknown Quantities', 'Checklist criteria: Can the learner use joining and separating to find unknown quantities?', 6, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('9b8c8e5a-2d81-4c79-ae5b-ed1accac2635', 'mathematics', '1', 'Patterns and Relationships', '2.1', 'checklist', 'Unknown Quantities', 'Checklist criteria: Can the learner use the inverse of the operation to represent and find unknown quantities?', 7, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('d9b02e79-0095-4cd8-8a98-a20e91ecf20a', 'mathematics', '1', 'Patterns and Relationships', '2.1', 'think-pair-share', 'Story Problems', 'Have learners read stories/situations about unknowns. Allow them to work in pairs and discuss representations/solutions', 8, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('e6a72706-6206-4ac9-ba7e-5cfab524afe9', 'mathematics', '1', 'Patterns and Relationships', '2.1', 'think-pair-share', 'Presentations', 'Allow learners to make presentations using concrete materials or role play situations to represent unknowns', 9, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('9aca9836-d91a-47b4-a97d-ba03b90ff682', 'mathematics', '1', 'Patterns and Relationships', '2.1', 'game-based', 'Missing Part Cards', 'Have learners play games in small groups using "missing part cards". Use number frames (5, 10, etc.). Each card can have a different number of dots in the frames or a specific number can be the focus', 10, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('e3e58b99-3857-4e7a-8ff8-debea5f7e885', 'mathematics', '1', 'Patterns and Relationships', '2.1', 'observation', 'Game Play', 'Observe and listen as students read the cards, discuss the visible parts, represent the unknown, etc. Model the game', 11, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('f4d01473-c3a6-4d25-ae01-6036082d5460', 'mathematics', '1', 'Patterns and Relationships', '2.1', 'game-based', 'I Wish I Had', 'Learners can also engage in the game "I wish I had…" They will listen to, observe or read situations and then determine the representation for the unknown', 12, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('3d47504e-5692-4437-bf2e-6d75af3ae7df', 'mathematics', '1', 'Patterns and Relationships', '2.1', 'game-based', 'Concrete/Pictorial', 'Concrete materials or pictures can be used with the presentation of the situations', 13, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('bd4aa271-64e1-4763-b4b8-8018b4483f73', 'mathematics', '1', 'Patterns and Relationships', '2.1', 'exit-ticket', 'Number Sentences', 'Distribute cards to learners and allow them to write/complete number sentences to represent unknowns from situations read to them', 14, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('a3321e65-c2f4-4517-b11b-3cbb44c942a6', 'mathematics', '1', 'Patterns and Relationships', '2.1', 'exit-ticket', 'Story Creation', 'OR distribute cards and allow students to write their own stories/situations for representing unknowns and complete them', 15, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('a86968c8-8f31-4c4a-ad00-b5e169d00f46', 'mathematics', '1', 'Patterns and Relationships', '2.1', 'exit-ticket', 'Display', 'Collect cards or allow students to place them up in specific area in the classroom for the topic done', 16, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('d80868b8-9719-469e-af51-bf5d1c3204dd', 'mathematics', '1', 'Patterns and Relationships', '2.2', 'group-work', 'Building Blocks', 'In pairs, learners create equal lengths using building blocks for given lengths', 1, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('d36fd765-7a71-43a0-aba1-3709eadf5e6a', 'mathematics', '1', 'Patterns and Relationships', '2.2', 'observation', 'Activity Tracking', 'Monitor using activity tracking tools', 2, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('384ce302-d861-4396-b3f3-b14365299eae', 'mathematics', '1', 'Patterns and Relationships', '2.2', 'checklist', 'Skills Monitoring', 'Activity: Create lengths of building blocks that are equivalent. Skills observed: Stacked the blocks one at a time keeping in mind the previous number', 3, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('b1006231-23ab-44bf-be5a-67bf46528856', 'mathematics', '1', 'Patterns and Relationships', '2.2', 'checklist', 'Skills Monitoring', 'Activity: Create lengths of building blocks that are equivalent. Skills observed: Stacked the blocks evenly as they created the equal lengths', 4, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('fc3fcc9e-e170-4066-9c69-52f8889e3f15', 'mathematics', '1', 'Patterns and Relationships', '2.2', 'checklist', 'Skills Monitoring', 'Activity: Manipulate a pair of given lengths to make them equivalent to each other. Skills observed: Added blocks to the shorter length', 5, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('251c7f1d-e405-4bb9-a50a-b9d9172e5e95', 'mathematics', '1', 'Patterns and Relationships', '2.2', 'checklist', 'Skills Monitoring', 'Activity: Manipulate a pair of given lengths to make them equivalent to each other. Skills observed: Removed blocks from the longer length', 6, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('6043c58e-cc16-441e-bed9-6b3e3bb5b7ea', 'mathematics', '1', 'Patterns and Relationships', '2.2', 'observation', 'Grid Matching', 'Determine whether students are able to match the equal lengths on a grid. Example: D = F', 7, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('675752d3-ca8a-4239-ac91-6983a10071dc', 'mathematics', '1', 'Patterns and Relationships', '2.2', 'rubric', 'Matching Equal Lengths', 'Rubric: The learner identified three pairs of equal lengths = 3 points', 8, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('1bf4730f-b378-46e8-9262-786b4377031b', 'mathematics', '1', 'Patterns and Relationships', '2.2', 'rubric', 'Matching Equal Lengths', 'Rubric: The learner identified 2 pairs of equal lengths = 2 points', 9, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('0d810629-253a-4a37-9cb1-6ca6a414a702', 'mathematics', '1', 'Patterns and Relationships', '2.2', 'rubric', 'Matching Equal Lengths', 'Rubric: The learner identified 1 pair of equal lengths = 1 point', 10, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('210c85a4-edfd-4501-80c6-dd473f205e64', 'mathematics', '1', 'Patterns and Relationships', '2.2', 'rubric', 'Matching Equal Lengths', 'Rubric: The learner identified no equal lengths = 0 points', 11, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('a18ba01c-46db-4f92-9a12-0d76d404bd42', 'mathematics', '1', 'Patterns and Relationships', '2.2', 'think-pair-share', 'Playing Cards', 'Learners are asked to create other number combinations equal to a given number combination using playing cards', 12, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('a1d18612-cbd9-43ee-8825-5564bd41c3a8', 'mathematics', '1', 'Patterns and Relationships', '2.2', 'think-pair-share', 'Guess and Check', 'Learners use the guess and check method to help them make equivalent playing card combinations', 13, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('7981b5bf-3c5a-4d7d-8c56-351ee04d2318', 'mathematics', '1', 'Patterns and Relationships', '2.2', 'think-pair-share', 'Marble Activity', 'Within a minute, learners individually draw marbles to create equal combinations for the given one. In their groups, discuss and compare their responses', 14, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('d4b5f550-cde4-418a-a419-4298e84e0a10', 'mathematics', '1', 'Patterns and Relationships', '2.2', 'think-pair-share', 'Card Combinations', 'Use the remaining cards in the suit to create the other equal combinations. Share their answers with the class', 15, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00');
INSERT INTO curriculum_assessment_strategies (id, subject, grade_level, strand, elo_number, strategy_type, strategy_category, description, sort_order, created_at, updated_at) VALUES
  ('c24af2f9-9db0-4a55-a588-495533031174', 'mathematics', '1', 'Patterns and Relationships', '2.2', 'think-pair-share', 'Dominoes', 'A similar assessment can be done using dominoes', 16, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('d9a1c401-ed74-4726-97b0-66a5ad86dd44', 'mathematics', '1', 'Patterns and Relationships', '2.2', 'exit-ticket', 'Combinations', 'Learners write another combination for a given combination on a given card', 17, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('ea35e546-8a06-4498-9bb6-fbb500f4bf22', 'mathematics', '1', 'Patterns and Relationships', '2.2', 'exit-ticket', 'Drawing', 'Learners complete representations to make equivalent number combinations. Example: Draw marbles to complete the following', 18, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('50410da0-036b-40fd-a58c-6e2c657037d6', 'mathematics', '1', 'Patterns and Relationships', '2.2', 'reflection', 'Number Lines', 'Learners compare three given number lines to identify the pair showing equal number combinations. They discuss how they can make the number combination shown on the non-example equal to the others identified', 19, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('0694268a-1a4b-4dbd-bade-5d3f8c3f7c88', 'mathematics', '1', 'Patterns and Relationships', '2.2', 'reflection', 'Odd One Out', 'Learners are given a set of dominoes to find the "odd one out". The number combination on one of the dominoes will not be equivalent to the others', 20, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('c2189c25-e66c-4f54-a8e5-c9eb5cfdd10e', 'mathematics', '1', 'Patterns and Relationships', '2.2', 'reflection', 'Reasoning', 'Learners state their reason for choosing the equal number combinations. They state the reason for not choosing the domino which does not belong to the set', 21, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('e122ed22-4d4e-47e4-baa5-83a56092fd35', 'mathematics', '1', 'Patterns and Relationships', '2.2', 'reflection', 'True/False', 'Learners analyze pairs of number combinations and check true or false to state whether the pair are equal number combinations', 22, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('8d6bbcd0-a2cb-4dca-a522-db1d81e82145', 'mathematics', '1', 'Patterns and Relationships', '2.3', 'observation', 'Pan Balance', 'Use a simple observation checklist while learners use the pan balance or arm balance to form equations', 1, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('a6493802-9d49-4317-b5d5-c7bc573f439a', 'mathematics', '1', 'Patterns and Relationships', '2.3', 'checklist', 'Equations', 'Checklist criteria: Uses counters correctly to maintain balance (Yes/No/Sometimes)', 2, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('1360885c-09e1-4c9c-8f82-15be26342cbd', 'mathematics', '1', 'Patterns and Relationships', '2.3', 'checklist', 'Equations', 'Checklist criteria: Correctly forms equations using counters', 3, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('417e62d5-5db7-447f-b3db-b66551bce973', 'mathematics', '1', 'Patterns and Relationships', '2.3', 'checklist', 'Equations', 'Checklist criteria: Expresses equalities as different representations of the same quantity', 4, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('63d59169-6b1b-4dd8-919a-7ad3420204af', 'mathematics', '1', 'Patterns and Relationships', '2.3', 'checklist', 'Equations', 'Checklist criteria: Formulates equations for given stories/word problems', 5, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('c19cc65f-486d-4092-a374-3ff83682260b', 'mathematics', '1', 'Patterns and Relationships', '2.3', 'checklist', 'Equations', 'Checklist criteria: Creates stories/word problems for given equations', 6, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('9a773111-e6bf-4d38-884a-8fcc4a603fdf', 'mathematics', '1', 'Patterns and Relationships', '2.3', 'checklist', 'Equations', 'Note: The checklist can be modified for the use of stackable blocks, as well as 5 and 10 frames', 7, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('b2fde896-e221-4386-9ef5-2826e6e18558', 'mathematics', '1', 'Patterns and Relationships', '2.3', 'talking-circles', 'Number Sentences', 'Have students pull their chairs and/or desks in a physical circle in the classroom', 8, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('cf556bc7-77ba-42d3-a65c-dba708d2c2be', 'mathematics', '1', 'Patterns and Relationships', '2.3', 'talking-circles', 'Number Sentences', 'The teacher calls out (or writes) three numbers and students are to formulate a number sentence using all three numbers', 9, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('39d2cb8f-1f64-466f-8a75-5fed504962b9', 'mathematics', '1', 'Patterns and Relationships', '2.3', 'talking-circles', 'Number Sentences', 'The first person to answer gets to hold a ball. This ball will be sent to the next person who answers correctly and so on', 10, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('19276ef4-7760-404f-8d6d-97d87f48ebdf', 'mathematics', '1', 'Patterns and Relationships', '2.3', 'game-based', 'Fishing Game', 'Have learners play fishing games in small groups to collect numbers that will make number sentences true', 11, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('99a87af8-a8d9-43a0-9fc4-fcc0a9cd58eb', 'mathematics', '1', 'Patterns and Relationships', '2.3', 'observation', 'Game Discussion', 'Observe learners as they discuss what is needed to make number sentences true and why', 12, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('0a82aa8e-1838-4931-a2a2-c8b731ce89a3', 'mathematics', '1', 'Patterns and Relationships', '2.3', 'think-pair-share', 'Scenarios', 'Allow learners to work in pairs or groups where they discuss different scenarios for given equations', 13, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('8d36fde9-5915-4876-8c36-52c9a910fb6d', 'mathematics', '1', 'Patterns and Relationships', '2.3', 'think-pair-share', 'Presentations', 'Provide them the opportunity to present to the class using concrete materials/role play/discussion', 14, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('835ee67b-161d-4dec-94c3-e3849b921c00', 'mathematics', '1', 'Patterns and Relationships', '2.3', 'think-pair-share', 'Mixed Ability', 'In mixed ability groups, allow learners to formulate equations for given word problems/stories. This provides an opportunity for struggling learners to become more engaged (inclusion)', 15, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('ec578b90-be99-421e-a047-508c38a25803', 'mathematics', '1', 'Patterns and Relationships', '2.3', 'think-pair-share', 'Explanation', 'Allow them to present, by reading the problem to the class and then explaining how they arrived at the equation. Ensure that each group member plays an active role in the activity', 16, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('7df5a7e2-bd5c-4b36-a289-3bdf1bcbab5c', 'mathematics', '1', 'Patterns and Relationships', '2.3', 'rubric', 'Presentations', 'Note: For presentations, a scoring rubric can be used as formative assessment', 17, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('b90a8a81-b5c0-467e-8f11-3a942653c695', 'mathematics', '1', 'Patterns and Relationships', '2.3', 'exit-ticket', 'Number Sentence', 'Ask learners to write a number sentence that equals 12', 18, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('70a6152d-48ca-4aac-9e30-c8115d5dfa82', 'mathematics', '1', 'Patterns and Relationships', '2.3', 'exit-ticket', 'Posting', 'Each learner will be given a blank card or sticky note to write his/her number sentence. These can be posted on a board in the classroom', 19, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('24b4cc44-4dcf-4524-a0c0-9bc79c4e8553', 'mathematics', '1', 'Patterns and Relationships', '1.1', 'diagnostic', 'Pattern Core', 'Diagnostic question: Can the student identify the pattern core?', 40, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('3841a310-55cc-4400-bf56-c960128ab98c', 'mathematics', '1', 'Patterns and Relationships', '1.1', 'diagnostic', 'Pattern Rule', 'Diagnostic question: Can the student describe the rule of a pattern?', 41, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('606e9b2b-6e65-44f6-bc64-b718a884975b', 'mathematics', '1', 'Patterns and Relationships', '1.1', 'diagnostic', 'Extending Patterns', 'Diagnostic question: Can the student extend a pattern in both directions?', 42, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('88a2a92b-4951-46f2-bb21-2aef0faf6833', 'mathematics', '1', 'Patterns and Relationships', '1.1', 'diagnostic', 'Pattern Translation', 'Diagnostic question: Can the student translate a pattern from one form to another?', 43, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('06324487-798b-490f-87b0-91902c37866d', 'mathematics', '1', 'Patterns and Relationships', '1.1', 'diagnostic', 'Error Detection', 'Diagnostic question: Can the student spot and correct errors in a pattern?', 44, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('eb2ee9bf-084d-4724-bc79-c9a4f74c7b9f', 'mathematics', '1', 'Patterns and Relationships', '1.1', 'diagnostic', 'Pattern Creation', 'Diagnostic question: Can the student create their own repeating pattern?', 45, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('7bcbe7fc-bfae-4dac-b447-80747c96e4c8', 'mathematics', '1', 'Patterns and Relationships', '1.2', 'diagnostic', 'Increasing Patterns', 'Diagnostic question: Can the student identify an increasing pattern?', 25, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('9d80acf3-29fb-43e7-8da0-0bee60ecdd5f', 'mathematics', '1', 'Patterns and Relationships', '1.2', 'diagnostic', 'Decreasing Patterns', 'Diagnostic question: Can the student identify a decreasing pattern?', 26, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('7075d0f9-d7f4-45dd-8e1d-6caae816053c', 'mathematics', '1', 'Patterns and Relationships', '1.2', 'diagnostic', 'Pattern Growth', 'Diagnostic question: Can the student explain how a pattern grows or shrinks?', 27, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('64e1588e-ec54-48e0-a38a-147c9053a313', 'mathematics', '1', 'Patterns and Relationships', '1.2', 'diagnostic', 'Growing Patterns', 'Diagnostic question: Can the student extend a growing pattern?', 28, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('5e7e79cf-ae91-4a56-977d-236f5b25e439', 'mathematics', '1', 'Patterns and Relationships', '1.2', 'diagnostic', 'Pattern Creation', 'Diagnostic question: Can the student create their own increasing/decreasing pattern?', 29, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('6e1b1379-126c-4ad1-968b-bde3d79cc967', 'mathematics', '1', 'Patterns and Relationships', '1.2', 'diagnostic', 'Error Detection', 'Diagnostic question: Can the student spot errors in increasing/decreasing patterns?', 30, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('e33bc324-41c8-41f1-b99a-3a189d9a8234', 'mathematics', '1', 'Patterns and Relationships', '2.1', 'diagnostic', 'Concrete Representation', 'Diagnostic question: Can the student represent unknowns using concrete materials?', 17, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('7abc2eec-f0e9-4cc5-971d-ebd21f9a6564', 'mathematics', '1', 'Patterns and Relationships', '2.1', 'diagnostic', 'Number Sentences', 'Diagnostic question: Can the student write number sentences with missing values?', 18, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('a2d450a6-03f5-41fa-ae6f-4a522de9a20b', 'mathematics', '1', 'Patterns and Relationships', '2.1', 'diagnostic', 'Part-Part-Whole', 'Diagnostic question: Can the student use part-part-whole relationships?', 19, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('d5aaa373-7cda-4d3d-9953-5a080ebe4c30', 'mathematics', '1', 'Patterns and Relationships', '2.1', 'diagnostic', 'Joining/Separating', 'Diagnostic question: Can the student solve joining and separating problems?', 20, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('f2a4009c-9105-4692-831e-e8c10b6d3bde', 'mathematics', '1', 'Patterns and Relationships', '2.1', 'diagnostic', 'Inverse Operations', 'Diagnostic question: Can the student use inverse operations?', 21, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('121232c3-765c-492b-862e-46c1550d2d29', 'mathematics', '1', 'Patterns and Relationships', '2.2', 'diagnostic', 'Equal Sets', 'Diagnostic question: Can the student create equal lengths/sets?', 23, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('1917e7a9-9164-4217-8cac-dcdefa63b50d', 'mathematics', '1', 'Patterns and Relationships', '2.2', 'diagnostic', 'Equivalent Combinations', 'Diagnostic question: Can the student identify equivalent number combinations?', 24, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('22174bef-b2f3-47b1-8270-14063aa10d1c', 'mathematics', '1', 'Patterns and Relationships', '2.2', 'diagnostic', 'Explaining Equality', 'Diagnostic question: Can the student explain why two quantities are equal?', 25, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('fae1cd18-a748-42bb-a4df-e5634c0ccce2', 'mathematics', '1', 'Patterns and Relationships', '2.2', 'diagnostic', 'Equal Sign', 'Diagnostic question: Can the student use the equal sign correctly?', 26, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('229e4faa-9d01-4263-a323-7ffc5f77eb08', 'mathematics', '1', 'Patterns and Relationships', '2.2', 'diagnostic', 'Odd One Out', 'Diagnostic question: Can the student find the "odd one out"?', 27, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('8b86571e-b94c-431b-9e82-fa3c9f05cee5', 'mathematics', '1', 'Patterns and Relationships', '2.3', 'diagnostic', 'Number Sentences', 'Diagnostic question: Can the student write number sentences for given situations?', 20, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('b980be25-188e-4da0-8617-f42a47469f64', 'mathematics', '1', 'Patterns and Relationships', '2.3', 'diagnostic', 'Pan Balance', 'Diagnostic question: Can the student use the pan balance to show equality?', 21, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00');
INSERT INTO curriculum_assessment_strategies (id, subject, grade_level, strand, elo_number, strategy_type, strategy_category, description, sort_order, created_at, updated_at) VALUES
  ('9e703530-b7de-4ea4-a00b-455d66aba7d2', 'mathematics', '1', 'Patterns and Relationships', '2.3', 'diagnostic', 'True/False Equations', 'Diagnostic question: Can the student determine if equations are true or false?', 22, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('036ec53e-b6e9-4fdf-8333-51defb6e7746', 'mathematics', '1', 'Patterns and Relationships', '2.3', 'diagnostic', 'Unknown Values', 'Diagnostic question: Can the student find unknown values in equations?', 23, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('de71df3b-52da-4143-b7b2-eb413918996f', 'mathematics', '1', 'Patterns and Relationships', '2.3', 'diagnostic', 'Word Problems', 'Diagnostic question: Can the student create word problems for equations?', 24, '2026-01-06T12:07:34.114351+00:00', '2026-01-06T12:07:34.114351+00:00'),
  ('ba60e9cb-3246-4846-9407-54c438c4c3b0', 'mathematics', '1', 'Measurement', '1.1', 'matching', 'Sentence Completion', 'Sample item: Picture of bird on tree - "The bird is _____(high, low) up on the tree."', 12, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('efab503d-e920-43e4-8786-dd3be852b4eb', 'mathematics', '1', 'Measurement', '1.1', 'matching', 'Sentence Completion', 'Sample item: Picture of boy and tree - "The boy is _____(near/far) to/from the tree."', 13, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('6fc3b801-a3de-4ed5-b226-76cf0942068b', 'mathematics', '1', 'Measurement', '1.1', 'observation', 'Vocabulary Listening', 'Listen to learners as they describe the characteristics of the attribute, length, of given objects. Check to see if the learner is using correct vocabulary associated with measurable attributes (length).', 1, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('4c049c7c-ca64-4bd9-a81d-70245ff1043c', 'mathematics', '1', 'Measurement', '1.1', 'checklist', 'Length Vocabulary', 'Checklist criteria: Can the student use the term "long" correctly?', 2, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('e6906248-604d-43ed-8354-bc6363a97f20', 'mathematics', '1', 'Measurement', '1.1', 'checklist', 'Length Vocabulary', 'Checklist criteria: Can the student use the term "short" correctly?', 3, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('269e381c-0baf-4ad7-a80f-79a5f1d8addc', 'mathematics', '1', 'Measurement', '1.1', 'checklist', 'Length Vocabulary', 'Checklist criteria: Can the student use the terms "near" and "far" correctly?', 4, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('2ba40346-3931-4424-b368-cf82ef165872', 'mathematics', '1', 'Measurement', '1.1', 'checklist', 'Length Vocabulary', 'Checklist criteria: Can the student use the terms "thick" and "thin" correctly?', 5, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('663fcb2b-8917-4e07-9f55-33ab41057cb6', 'mathematics', '1', 'Measurement', '1.1', 'checklist', 'Length Vocabulary', 'Checklist criteria: Can the student use the terms "narrow" and "wide" correctly?', 6, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('2ef71a0d-7af8-47f5-a56f-7c6e719092d2', 'mathematics', '1', 'Measurement', '1.1', 'checklist', 'Length Vocabulary', 'Checklist criteria: Can the student use the terms "deep" and "shallow" correctly?', 7, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('3df2cc65-04ff-4053-9824-05f12e6f281f', 'mathematics', '1', 'Measurement', '1.1', 'think-pair-share', 'Story-Based Assessment', 'As the story "Goldilocks and the Three Bears" is read, the teacher will take note of the responses from students about the vocabulary associated with the contents in the container (full and empty).', 8, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('0edc90b9-be13-4772-a509-0a6b8446e115', 'mathematics', '1', 'Measurement', '1.1', 'think-pair-share', 'Classification Pictures', 'Situations classifying empty and full containers in pictures will be done by students first using their self-check table in pairs then presented orally to the class.', 9, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('9afc4e28-9221-4e36-8ff4-9068c2b1c8d8', 'mathematics', '1', 'Measurement', '1.1', 'matching', 'Sentence Completion', 'In pairs, students will discuss and match the picture to the sentence that best describes it and fill in the blank space with the correct describing word.', 10, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('08d747f2-0d82-4791-91b7-f8b46a8a86ff', 'mathematics', '1', 'Measurement', '1.1', 'matching', 'Sentence Completion', 'Sample item: Picture of bus and building - "The bus is _____(close, far) to/from the building."', 11, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('48b07769-da02-40f6-a30b-4d6a8b1c73b4', 'mathematics', '1', 'Measurement', '1.1', 'matching', 'Sentence Completion', 'Sample item: Picture of baby in pool - "Babies should bathe in pools that are _____(shallow, deep)."', 14, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('60ddbdac-8980-4619-8c50-2daa254ac3cd', 'mathematics', '1', 'Measurement', '1.1', 'matching', 'Sentence Completion', 'Sample item: Picture of mangoes on tree - "The mangoes can be easily reached because they are _____(low, high) on the tree."', 15, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('92cd33c1-8869-467e-868f-2a0a37285f85', 'mathematics', '1', 'Measurement', '1.1', 'graphic-organizer', 'Vocabulary Culmination', 'To culminate the measuring attribute, length, a graphic organizer will be created with learners with all the describing words/vocabulary learnt about how long or short objects and distances are. A discussion will bring out the measuring attribute of length.', 16, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('f7ed0950-998e-4e25-a7f4-396fcc02345b', 'mathematics', '1', 'Measurement', '1.1', 'observation', 'Capacity - Pouring', 'Teacher will observe students as they pour items into containers and group the objects as liquids that can be poured (takes up the space of the container) and items that can be poured and not liquid (not taking up all the space). Students will formalise the measuring attribute capacity from the activities.', 17, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('bf895692-2b47-423d-8e12-1999c07cfcbe', 'mathematics', '1', 'Measurement', '1.1', 'worksheet', 'Capacity Identification', 'Place an X on all the items that can be poured and the container has a capacity.', 18, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('f3833389-4abe-41a1-8000-25ff276c3225', 'mathematics', '1', 'Measurement', '1.1', 'think-pair-share', 'Heavy/Light Classification', 'In pairs, think of objects that are heavy, objects that are light to carry around them and group them (pictures will be given as well for that discussion). Students will share with the class after classifying the objects as heavy or light.', 19, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('b6c92c5a-079e-4ac6-80dd-ddbc5ff1e9aa', 'mathematics', '1', 'Measurement', '1.1', 'graphic-organizer', 'Mass Vocabulary', 'All the terms associated with mass will be discussed with students and a graphic organizer will be created to assess their understanding of mass.', 20, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('58817997-c864-492b-adc0-cc1e8525c621', 'mathematics', '1', 'Measurement', '1.1', 'observation', 'Area - Pizza Making', 'As students engage in the pizza making process, teacher will note the vocabulary associated with the area (small and large) as they discuss the activity.', 21, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('f070a775-fac8-4b8d-b966-25938c4d5d00', 'mathematics', '1', 'Measurement', '1.1', 'observation', 'Surface Description', 'Students will be presented with some objects to feel and touch them. They will describe what they feel (in terms of the surfaces). Teacher will listen for vocabulary such as flat surface/face, curved surface.', 22, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('01cbcc3c-66a4-40c4-a6ee-f3756d98b5bb', 'mathematics', '1', 'Measurement', '1.2', 'observation', 'Station Observation', 'Listen to the discussions at various stations on which objects are shorter, longer and taller. Pay attention to the skills applied and the reason for selection. Make use of observational checklists.', 23, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('5f2f8206-d23e-4c6a-9a4d-223017b24586', 'mathematics', '1', 'Measurement', '1.2', 'checklist', 'Comparing Length/Height', 'Checklist criteria: Did the children place both objects on the same flat surface to compare their height?', 24, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('e9b1ab8e-5045-46ae-bd6d-248e163ddc30', 'mathematics', '1', 'Measurement', '1.2', 'checklist', 'Comparing Length/Height', 'Checklist criteria: Can the student identify taller or shorter objects?', 25, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('a9d4f564-2d1a-4ff1-af9b-d86f3f7cefa2', 'mathematics', '1', 'Measurement', '1.2', 'checklist', 'Comparing Length/Height', 'Checklist criteria: Did the student use the same start point to compare the length of the two objects?', 26, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('e9e948bf-0c02-4016-a69b-cd86ece0398c', 'mathematics', '1', 'Measurement', '1.2', 'checklist', 'Comparing Length/Height', 'Checklist criteria: Can the student recognize the longer and shorter object?', 27, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('945f5445-0a9c-4d57-b64e-33f557c3eb8f', 'mathematics', '1', 'Measurement', '1.2', 'checklist', 'Comparing Length/Height', 'Checklist criteria: Can the student explain why objects must be aligned before they can be compared?', 28, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('f5fd09cf-27e5-4a84-9dbf-97698d02c67d', 'mathematics', '1', 'Measurement', '1.2', 'task-sheet', 'Which Mathematician is Right?', 'Provide students with a task sheet with objects identified as longer than or shorter than other objects. Have students determine which is correct and explain why.', 29, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('f44fe339-0a9b-4730-acf0-8aefede359b0', 'mathematics', '1', 'Measurement', '1.2', 'game-based', 'Hoopla Game', 'Pay attention to which objects students are trying to send the hoop around after instructions are given (e.g., "Send the hoop around the object which is nearer to you"). Focus on whether students are attempting to send the hoop around the correct object.', 30, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('66590b5e-49c7-4bc9-b3e3-389ee8203f48', 'mathematics', '1', 'Measurement', '1.2', 'think-pair-share', 'Comparison Statements', 'Listen as students make statements of comparison. Question students to find out their reasoning for such statements. Watch as students pick their cards to show that they have completed their task. Pay careful attention to the use of the words higher and lower in the explanations given.', 31, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('47236132-2d6a-48ec-a07c-977efa856ae0', 'mathematics', '1', 'Measurement', '1.2', 'product', 'Model Building', 'Observe as learners glue sticks to make models of thicker, thinner, narrower and wider shelves. Provide students with the opportunity to show their work and explain by making statements of comparison.', 32, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('1360a88d-fcc5-4e3e-acf8-452ee189363c', 'mathematics', '1', 'Measurement', '1.2', 'think-pair-share', 'Mass Comparison', 'Have every child show their objects to their pairs, identify which is lighter or heavier. Question students to further explain why they made such a comparison statement. Have them work in a small group to verify their answer using a hanger balance scale.', 33, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('de86f868-06dd-4203-91cb-06995f1014e6', 'mathematics', '1', 'Measurement', '1.2', 'game-based', 'Seesaw Groups', 'Have students form three groups: lighter than, heavier than, or equal in weight. After students take turns on the seesaw with their partner, they fit themselves in the right groups. After the activity, have each child state their position in comparison to their partner (e.g., "I am heavier than Joe").', 34, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('9551f304-e5aa-40ca-9c0b-792aa0b8ceb7', 'mathematics', '1', 'Measurement', '1.2', 'group-work', 'Push/Pull Selection', 'In groups, have them select two objects - one which can be pushed or pulled and one which they can''t. Provide learners with the opportunity to present objects to the class giving explanations with reasoning. Pay attention to the use of the terms heavier than and lighter than.', 35, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('bd3f48b1-be35-410d-9a1b-3282f0241b51', 'mathematics', '1', 'Measurement', '1.2', 'demonstration', 'Capacity Comparison', 'Allow students to visit different demonstration stations. Have groups explain the process they followed to determine which bottle holds more or less liquid or equal amounts of liquid. Allow students to ask questions if they need to know anything more about the process followed.', 36, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('cef636a0-c70b-4e70-8d36-22c9bd8e2366', 'mathematics', '1', 'Measurement', '1.2', 'think-pair-share', 'Area Comparison', 'Pay attention to students as they compare the surface area of the books chosen. Let them discuss in pairs, as they make statements of comparison. Provide students with the opportunity to share with the class.', 37, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('7def5754-22bb-488a-961f-5dbb69c0216a', 'mathematics', '1', 'Measurement', '1.3', 'observation', 'Unit Selection', 'Observe pupils as they select non-standard units to measure the different attributes.', 38, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('d28bdbc6-7e32-4445-be1f-8f90ce19c86f', 'mathematics', '1', 'Measurement', '1.3', 'observation', 'Reasoning Notes', 'Make notes of students'' reasoning as they discuss among themselves the difference in their answers.', 39, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('ea555a0d-9aad-472a-a701-d72a3e21db76', 'mathematics', '1', 'Measurement', '1.3', 'game-based', 'Appropriate Unit Selection', 'Students use the appropriate non-standard measurement to measure items: Hands span, toy cars, foot span for length; Stone & sand for capacity; Hand span and squares for area.', 40, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('19efb99b-4d21-4489-9915-fce53f5a1544', 'mathematics', '1', 'Measurement', '1.3', 'estimation', 'Estimate Then Measure', 'Students estimate the non-standard measurement then measure the object. Students should justify their reasons for their estimated non-standard measurement.', 41, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('dc8b45fc-899d-4472-add2-c7a6c9ca0c7e', 'mathematics', '1', 'Measurement', '1.3', 'comparison', 'Object Comparison', 'Compare the length of an object (pencil) to the length of two or three smaller objects (eraser, sharpener).', 42, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('3294e7e9-3b61-4cb1-99be-d4db55ecd474', 'mathematics', '1', 'Measurement', '1.3', 'comparison', 'Surface Comparison', 'Compare a surface space with two different size and shape leaves. (How many banana leaves/other leaves can cover the chalkboard? How many table mats/coasters can cover a table surface?)', 43, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('715eb8df-1316-4600-b30e-772d464de648', 'mathematics', '1', 'Measurement', '1.3', 'product', 'Building Comparison', 'Use blocks or tiles to build something longer than, same as, shorter than, or half as long as a given object.', 44, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('08da9a4d-565f-458e-b8c2-1a6a0c6ecd31', 'mathematics', '1', 'Measurement', '1.3', 'experiment', 'Group/Pair Measurement', 'Students work in groups or pairs to estimate measurement using non-standard units using various objects.', 45, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('da55903c-743e-4711-9720-6591f4afca28', 'mathematics', '1', 'Measurement', '1.3', 'experiment', 'Surface Covering', 'Students cover the surface of items using different sized squares or palms.', 46, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('de308868-d929-4242-a1a1-e323f7dcf037', 'mathematics', '1', 'Measurement', '1.3', 'experiment', 'Measurement Comparison', 'Students compare measurements using non-standard measurement in groups or pairs.', 47, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00');
INSERT INTO curriculum_assessment_strategies (id, subject, grade_level, strand, elo_number, strategy_type, strategy_category, description, sort_order, created_at, updated_at) VALUES
  ('a7ecb91d-a579-42e8-b4c4-7e80cdd2a250', 'mathematics', '1', 'Measurement', '1.3', 'math-talk', 'Discussion Assessment', 'Students discuss their findings: "Why is his or her measurement more or less than yours?" "Why is there a difference in the measurements?"', 48, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('c936c6d9-dbc5-453b-86e6-a9c97029bda7', 'mathematics', '1', 'Measurement', '1.3', 'math-talk', 'Container Comparison', 'Students use different size containers to determine which holds more.', 49, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('c5aacf61-5e84-4c50-b966-1ad40a20b652', 'mathematics', '1', 'Measurement', '1.3', 'math-talk', 'Three Object Comparison', 'Provide students with three or more objects and have them compare all three.', 50, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('ff0104aa-a99a-42eb-bfd5-ae45de020899', 'mathematics', '1', 'Measurement', '1.3', 'checklist', 'Non-Standard Measurement', 'Checklist criteria: Can the student select appropriate non-standard units?', 51, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('e6238b1d-c644-474f-a77d-d5838f0d02d3', 'mathematics', '1', 'Measurement', '1.3', 'checklist', 'Non-Standard Measurement', 'Checklist criteria: Can the student estimate before measuring?', 52, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('35ff55ae-5007-4410-abfe-f024c5d03868', 'mathematics', '1', 'Measurement', '1.3', 'checklist', 'Non-Standard Measurement', 'Checklist criteria: Can the student measure length using body parts (hand span, foot span)?', 53, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('3266cd21-82d1-4e75-a82e-0a2a676e4ab2', 'mathematics', '1', 'Measurement', '1.3', 'checklist', 'Non-Standard Measurement', 'Checklist criteria: Can the student measure length using objects (paper clips, blocks)?', 54, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('5edb8dbb-a63c-4152-8c1b-98b052870777', 'mathematics', '1', 'Measurement', '1.3', 'checklist', 'Non-Standard Measurement', 'Checklist criteria: Can the student measure area using non-standard units?', 55, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('1c6befdd-8b4b-401d-b3ed-3554750bde3e', 'mathematics', '1', 'Measurement', '1.3', 'checklist', 'Non-Standard Measurement', 'Checklist criteria: Can the student measure capacity using non-standard units?', 56, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('07732de3-4179-4a93-b838-0ba2ec75772a', 'mathematics', '1', 'Measurement', '1.3', 'checklist', 'Non-Standard Measurement', 'Checklist criteria: Can the student explain differences in measurements?', 57, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('d0243336-98bf-40a2-a3e1-8847bfa6a454', 'mathematics', '1', 'Measurement', '1.4', 'online-game', 'Days of the Week', 'Select the correct day to complete the sentences. Online resource: https://wordwall.net/resource/22419293', 58, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('adbbc95e-9181-45a6-94d1-b7326f19fcb5', 'mathematics', '1', 'Measurement', '1.4', 'online-game', 'Months Ordering', 'Put the months of the year in the correct order. Online resource: https://wordwall.net/resource/363117', 59, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('9640241f-051f-4586-a073-6306ecdfd182', 'mathematics', '1', 'Measurement', '1.4', 'writing', 'Story/Poem Construction', 'With the aid of a calendar, in small groups, students construct a story or poem utilizing the days, months, or dates in a sequential order. For example, students with the same birth month can identify each birthdate in sequential order.', 60, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('8534cbd4-4783-44e4-bb65-2f448cd6a229', 'mathematics', '1', 'Measurement', '1.4', 'writing', 'Calendar Marking', 'Use a calendar to mark special days celebrated in their country.', 61, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('b717940c-765e-4697-a718-1a90e255103d', 'mathematics', '1', 'Measurement', '1.4', 'art', 'Month Drawing', 'Draw images to represent their favourite month of the year.', 62, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('17f73267-ab08-4b26-8cd4-e05145cd1b71', 'mathematics', '1', 'Measurement', '1.4', 'worksheet', 'Sequence Completion', 'Complete the days of the week or months of the year starting from a given day or month (e.g., Complete by filling in the days of the week from Thursday, _____, _____, _____).', 63, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('a35c47ee-c5e6-401d-9816-ec55f349837f', 'mathematics', '1', 'Measurement', '1.4', 'worksheet', 'Clock Worksheet', 'Students complete a worksheet in which they draw hands to show time on analog clocks.', 64, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('e7cbc24b-eb5d-491f-a963-c86eb66da016', 'mathematics', '1', 'Measurement', '1.4', 'kinesthetic', 'Human Body Clock', 'Students work in pairs to tell the time using their bodies.', 65, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('6f148dcb-a0bf-42e5-8fb3-9b7e20408e63', 'mathematics', '1', 'Measurement', '1.4', 'online-game', 'Tell the Time Games', 'Online resources for telling time practice: https://wordwall.net/resource/24859817, https://wordwall.net/resource/32922747, https://wordwall.net/resource/54049357, https://wordwall.net/resource/363099', 66, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('1088b025-1204-4568-b59b-5fa397374401', 'mathematics', '1', 'Measurement', '1.4', 'matching', 'Time of Day Matching', 'Students match a series of activities to the correct time of the day when each activity occurs. Students can justify their answers if they differ (e.g., a student may say he or she takes an afternoon nap and another may say it only happens in the evening).', 67, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('bf527579-47f6-4976-899f-3d55d0bc23b3', 'mathematics', '1', 'Measurement', '1.4', 'observation', 'Days Calculation', 'Get students to work out how many days they have been in school using the yearly calendar. Get them to also work out how many days to other significant events such as Christmas, their birthday, or the school holidays. Students can create their own questions to swap with another student to answer.', 68, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('f272cbc0-02ba-4a59-83ac-59c5fafa6688', 'mathematics', '1', 'Measurement', '1.4', 'oral-questioning', 'Coin Features', 'Students identify the features of the different coins in their country through comparing and contrasting all the coins.', 69, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('b811036f-b387-44db-9059-dc2e5e0ea7e6', 'mathematics', '1', 'Measurement', '1.4', 'hands-on', 'Coin Sorting', 'Sort and arrange the coins according to value.', 70, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('3ec0719e-5788-414f-991d-e27c17fc996a', 'mathematics', '1', 'Measurement', '1.4', 'hands-on', 'Coin Combinations', 'Give combinations of coins that give a total value of 10c and 25c.', 71, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('2ccd8ab1-4016-4b97-8eee-a43d41025bb8', 'mathematics', '1', 'Measurement', '1.4', 'checklist', 'Calendar and Time', 'Checklist criteria: Can the student state the days of the week in order?', 72, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('2d183103-1cae-4050-acdc-805fa4cedf6e', 'mathematics', '1', 'Measurement', '1.4', 'checklist', 'Calendar and Time', 'Checklist criteria: Can the student state the months of the year in order?', 73, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('a847270a-0562-4186-9568-638ea9de5a6a', 'mathematics', '1', 'Measurement', '1.4', 'checklist', 'Calendar and Time', 'Checklist criteria: Can the student read a date on the calendar?', 74, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('9088c3b2-bd27-4b49-8f60-48cc90803b62', 'mathematics', '1', 'Measurement', '1.4', 'checklist', 'Calendar and Time', 'Checklist criteria: Can the student identify holidays on the calendar?', 75, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('82ba246d-b6d0-4145-830d-957f6d0bd574', 'mathematics', '1', 'Measurement', '1.4', 'checklist', 'Calendar and Time', 'Checklist criteria: Can the student tell time on the hour (analog)?', 76, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('54437002-d017-4d7b-85eb-90b0bb126235', 'mathematics', '1', 'Measurement', '1.4', 'checklist', 'Calendar and Time', 'Checklist criteria: Can the student tell time at half past (analog)?', 77, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('97afc4c0-390f-451a-a5c8-705e548c8b44', 'mathematics', '1', 'Measurement', '1.4', 'checklist', 'Calendar and Time', 'Checklist criteria: Can the student read time on a digital clock?', 78, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('d47111bb-4e48-441e-99d7-4837b4638191', 'mathematics', '1', 'Measurement', '1.4', 'checklist', 'Calendar and Time', 'Checklist criteria: Can the student match activities to time of day?', 79, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('26c43422-727d-4f25-a0c4-9d03aa8ef9c5', 'mathematics', '1', 'Measurement', '1.4', 'checklist', 'Money', 'Checklist criteria: Can the student identify the 5c coin?', 80, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('5ab258d7-4824-4468-96bc-b86384a3083f', 'mathematics', '1', 'Measurement', '1.4', 'checklist', 'Money', 'Checklist criteria: Can the student identify the 10c coin?', 81, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('72af5075-fba1-48af-87c0-3f68a9844de9', 'mathematics', '1', 'Measurement', '1.4', 'checklist', 'Money', 'Checklist criteria: Can the student identify the 25c coin?', 82, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('5bc06c55-d1be-4c4f-a6f3-f4f77f672833', 'mathematics', '1', 'Measurement', '1.4', 'checklist', 'Money', 'Checklist criteria: Can the student sort coins by value?', 83, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('fd03bd0d-4038-47f2-adf1-29e442bc37a9', 'mathematics', '1', 'Measurement', '1.4', 'checklist', 'Money', 'Checklist criteria: Can the student count coins to make a given value?', 84, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('b1f58080-f6a7-4e27-8102-276c38bcf7bf', 'mathematics', '1', 'Measurement', '1.4', 'checklist', 'Money', 'Checklist criteria: Can the student skip count by 5s using coins?', 85, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('da63127c-bf09-484b-bf8c-19670c06c92a', 'mathematics', '1', 'Measurement', '1.4', 'checklist', 'Money', 'Checklist criteria: Can the student skip count by 10s using coins?', 86, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('c0d74b19-e5ec-437e-81a1-6f16b602d1e9', 'mathematics', '1', 'Data Handling and Probability', '1.1', 'observation', 'Question Formulation', 'Listen to students as they formulate questions during the observation process based on the experiences provided by the teacher (nature walk, concrete objects, etc.). Check to ensure that the questions generated are related to what was observed.', 87, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('c96ec912-11a0-4e58-b59c-49cc02384228', 'mathematics', '1', 'Data Handling and Probability', '1.1', 'oral-questioning', 'Answer Checking', 'Listen to students'' answers based on the questions they construct. Check to make sure that answers supplied are related or possible. Follow-up questions can be asked to check students'' understanding.', 88, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('a586d7f7-ed9c-4d81-9fc2-9196ce312f1e', 'mathematics', '1', 'Data Handling and Probability', '1.1', 'oral-questioning', 'Picture/Object Questioning', 'Ask probing questions such as: "What would you like to know about this picture/objects/people?"', 89, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('8930cc95-1096-4d7f-b64f-07693c9ad036', 'mathematics', '1', 'Data Handling and Probability', '1.1', 'peer-evaluation', 'Question Evaluation', 'Listen to students as they evaluate their peers as they ask questions to be used to collect data.', 90, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('d70b5b5e-6dc0-4b8f-b5be-aafeb36a8201', 'mathematics', '1', 'Data Handling and Probability', '1.1', 'conference', 'Question Formation', 'Conference students concerning their efforts at putting words together to form questions based on a situation (shapes, coins, pictures, sports). Example: "(cents many are How coins jar the five in?)"', 91, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('b612ebbc-bebc-4159-b04f-1ead5dbb8568', 'mathematics', '1', 'Data Handling and Probability', '1.1', 'game-based', 'Fish for a Question', 'Observe as students select random questions from a fish bowl; read each question, then state which data set they would use to get the information to answer the question. Non-examples should be provided to monitor students'' understanding.', 92, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('29cb9348-aab4-41d0-a866-d78b8e1907f4', 'mathematics', '1', 'Data Handling and Probability', '1.1', 'game-based', 'Fish Bowl Questions', 'Sample questions: "How many bananas are in the bowl?" "Of all the shapes, which one has the most squares?" "Who has the least number of marbles?" "What is the gender of the tallest child?" "On which day were the most mangoes sold?"', 93, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('a5062689-33c8-45a4-b6b4-6a05c8dbfaac', 'mathematics', '1', 'Data Handling and Probability', '1.1', 'matching', 'Question-Source Matching', 'Observe students match questions to possible sources where data can be had to answer these questions; and how they justify their responses.', 94, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('659d409a-8924-4762-b6d7-ac550aebb960', 'mathematics', '1', 'Data Handling and Probability', '1.1', 'group-work', 'Error Correction', 'Observe students as they work in small groups to correct questions with errors to make them clearer and/or more specific.', 95, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('f9950b1c-0fe9-423c-a2b6-3e274afac497', 'mathematics', '1', 'Data Handling and Probability', '1.1', 'role-play', 'Interview Observation', 'Observe students as they interview each other based on selected scenarios/learning experiences presented. Students take turns to construct and ask questions according to the scenario presented.', 96, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('6a6bfd69-5b89-4b54-8061-dd61bc81b912', 'mathematics', '1', 'Data Handling and Probability', '1.2', 'checklist', 'Data Collection', 'Use a checklist to assess students as they engage in collecting and recording data. Assess their ability to record data accurately using different methods.', 97, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00');
INSERT INTO curriculum_assessment_strategies (id, subject, grade_level, strand, elo_number, strategy_type, strategy_category, description, sort_order, created_at, updated_at) VALUES
  ('80a22a88-a424-4c00-b539-04033d3f06ed', 'mathematics', '1', 'Data Handling and Probability', '1.2', 'oral-questioning', 'Strategy Justification', 'Listen to students as they work in pairs and small groups to provide justification for choice of strategies used in collecting and recording data.', 98, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('fd937be7-4fcc-4040-9329-f70e37732c7f', 'mathematics', '1', 'Data Handling and Probability', '1.2', 'oral-questioning', 'Grouping Explanation', 'Students answer questions to justify why they group objects the way they did.', 99, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('b0e369dd-6939-478d-bedf-6377ef995595', 'mathematics', '1', 'Data Handling and Probability', '1.2', 'think-pair-share', 'Data Representation', 'Students work together to represent data collected.', 100, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('57fbb049-1aa3-4058-8f4f-ff5c80c81476', 'mathematics', '1', 'Data Handling and Probability', '1.2', 'observation', 'Tally Construction', 'Observe students as they construct charts (such as tally charts, drawings, matching diagrams, arrow diagrams, etc.) to record the number of objects/people observed in selected places at a given time (people wearing different colours, vehicle colours, vehicle brands, etc.).', 101, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('f8943269-683b-4adc-8e11-2fde3ad99694', 'mathematics', '1', 'Data Handling and Probability', '1.2', 'product', 'Display Board Creativity', 'Teachers make notes of students'' creativity as they mount display boards depicting the same data in an organised manner in different ways.', 102, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('614d2992-a861-4fce-9efd-f508674cf666', 'mathematics', '1', 'Data Handling and Probability', '1.2', 'product', 'Concrete Bar Chart', 'Students represent data collected relating to their birth months, daily temperature, ages of their classmates, etc. Teacher interviews students as they use concrete objects (square tiles, counters, grid papers) to construct bar charts for collected and/or given data.', 103, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('3525a6b6-c09e-4b94-9422-04b825a78e50', 'mathematics', '1', 'Data Handling and Probability', '1.2', 'product', 'Pictograph Presentation', 'Students present data based on different topics (birth months of students, occupations of parents, ethnicity groupings in the class/schools, tourist sightings, preferred taste in foods, preferred festivals, modes of transportation used to travel to school, etc.).', 104, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('57df453b-00fb-45f7-9b88-8b54a40ea75a', 'mathematics', '1', 'Data Handling and Probability', '1.2', 'hands-on', 'Sorting Assessment', 'Example: Sort cotton balls according to the correct colour.', 105, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('5a90adf9-7959-4194-b71c-8dcfc1164fd7', 'mathematics', '1', 'Data Handling and Probability', '1.2', 'checklist', 'Data Collection Skills', 'Checklist criteria: Can the student formulate questions based on observation?', 106, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('62065d1e-5a5f-4de6-8cf4-58b921c2ea75', 'mathematics', '1', 'Data Handling and Probability', '1.2', 'checklist', 'Data Collection Skills', 'Checklist criteria: Can the student identify sources for collecting data?', 107, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('e1af046c-1b3a-459e-a132-42cfce4e8f41', 'mathematics', '1', 'Data Handling and Probability', '1.2', 'checklist', 'Data Collection Skills', 'Checklist criteria: Can the student collect data through observation?', 108, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('daf0c8ef-2386-4bf2-b114-05632d718068', 'mathematics', '1', 'Data Handling and Probability', '1.2', 'checklist', 'Data Collection Skills', 'Checklist criteria: Can the student record data accurately?', 109, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('815b1fc6-ea28-4811-bfc9-acbc6bbe5c01', 'mathematics', '1', 'Data Handling and Probability', '1.2', 'checklist', 'Data Collection Skills', 'Checklist criteria: Can the student sort data by one attribute?', 110, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('fba96178-ec9e-4563-90d3-cf4b4bbc0307', 'mathematics', '1', 'Data Handling and Probability', '1.2', 'checklist', 'Data Collection Skills', 'Checklist criteria: Can the student organize data in a tally chart?', 111, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('9e174bc1-1fb0-4095-8ef5-93cb656f6dfe', 'mathematics', '1', 'Data Handling and Probability', '1.2', 'checklist', 'Data Collection Skills', 'Checklist criteria: Can the student create a pictograph?', 112, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('a8cce339-959c-41ab-872c-16da2620ddf7', 'mathematics', '1', 'Data Handling and Probability', '1.2', 'checklist', 'Data Collection Skills', 'Checklist criteria: Can the student create a bar graph?', 113, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('43709a73-db0a-4e59-aaf4-8c77de1ffa6f', 'mathematics', '1', 'Data Handling and Probability', '1.3', 'checklist', 'Ordering Data', 'Use a checklist to assess students as they arrange items from greatest to smallest in a graph (pictograph, concrete graph, etc.).', 114, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('929badcd-be80-435e-86a1-838414a7866c', 'mathematics', '1', 'Data Handling and Probability', '1.3', 'peer-evaluation', 'Peer Reflection', 'Observe students working in pairs, as they reflect on the work of their peers against formulated criteria; and students give suggestions for improvements.', 115, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('19279069-8646-4246-8d23-940409e8f34e', 'mathematics', '1', 'Data Handling and Probability', '1.3', 'game-based', 'Height Arrangement', 'Students play a game in which they arrange themselves according to their heights (tallest to shortest).', 116, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('07eeaa9c-f879-4691-965a-c5c7b961a90f', 'mathematics', '1', 'Data Handling and Probability', '1.3', 'interview', 'Strategy Interview', 'Make notes of and interview students concerning the strategies they used to order members of a data set. Sample question: "How did you know you arranged yourselves correctly?"', 117, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('a96b1d19-cfbb-4c16-ba61-49c9d5813d1e', 'mathematics', '1', 'Data Handling and Probability', '1.3', 'interview', 'Strategy Responses', 'Possible student responses: "We aligned ourselves in pairs first and our classmates checked to ensure that we were lined up properly" / "We picked the tallest and shortest in the group then the others fell in place in the line up."', 118, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('c5cf53b8-0197-4122-ba21-dd96cdcb9d61', 'mathematics', '1', 'Data Handling and Probability', '1.3', 'observation', 'Feedback Application', 'Take notes of students as they use the feedback of their peers to identify improvements and adjust the quality of their work.', 119, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('56974cf6-aa7e-4d94-a4f4-d64b38de9074', 'mathematics', '1', 'Data Handling and Probability', '1.3', 'oral-questioning', 'Order Justification', 'Listen to students as they justify the order for which they placed the items on their graph. Ask questions to ensure that they can distinguish between large and small numbers in data sets.', 120, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('650626a1-b675-4f42-a3d3-9cfc45c77d0f', 'mathematics', '1', 'Data Handling and Probability', '1.3', 'checklist', 'Data Analysis', 'Checklist criteria: Can the student order data from greatest to least?', 121, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('55b8c9bc-b165-4c05-98cc-67614faf333b', 'mathematics', '1', 'Data Handling and Probability', '1.3', 'checklist', 'Data Analysis', 'Checklist criteria: Can the student identify the highest value in data set?', 122, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('d36796cb-3af8-48fd-a2db-97ad5398d734', 'mathematics', '1', 'Data Handling and Probability', '1.3', 'checklist', 'Data Analysis', 'Checklist criteria: Can the student identify the lowest value in data set?', 123, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('d213f288-9719-4069-b3d4-9c7c2e0e3c81', 'mathematics', '1', 'Data Handling and Probability', '1.3', 'checklist', 'Data Analysis', 'Checklist criteria: Can the student compare values in a data set?', 124, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('c05a629d-2e75-453b-89a9-1813743f288c', 'mathematics', '1', 'Data Handling and Probability', '1.3', 'checklist', 'Data Analysis', 'Checklist criteria: Can the student explain strategies used for ordering?', 125, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('b45e025a-729b-40df-82d8-408bbaf7487d', 'mathematics', '1', 'Data Handling and Probability', '1.4', 'oral-questioning', 'Graph Interpretation', 'Listen to students; take notes of and give feedback to them as they use information from graphs, pictographs, charts and tables to answer questions.', 126, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('23ee21e6-4c2e-4853-8cb4-81d3a818d9b1', 'mathematics', '1', 'Data Handling and Probability', '1.4', 'oral-questioning', 'Correct Answers', 'Students answer questions correctly based on the information presented in bar graphs, pictographs, etc.', 127, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('4dfe6b2f-4802-49e9-8b21-b6e9bedc17e8', 'mathematics', '1', 'Data Handling and Probability', '1.4', 'oral-questioning', 'Fruit Pictograph Questions', 'Sample questions for pictograph (Fruit Preferences): "How many children prefer apples?" "Which fruit is least preferred?" "How many more children prefer pears than bananas?"', 128, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('6bd52589-6b68-4ae4-bb5b-9ac4e68c8b49', 'mathematics', '1', 'Data Handling and Probability', '1.4', 'group-work', 'Question Construction', 'Have students work in small groups to construct questions containing the vocabulary "least," "most," "more than," "less than" that can be answered using a given data set. Students from different groups exchange questions and give feedback to each other on the clarity of the questions.', 129, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('9370b41f-538d-48f1-8a6b-8880402663ad', 'mathematics', '1', 'Data Handling and Probability', '1.4', 'oral-presentation', 'Graph Understanding', 'Students demonstrate their understanding of the graph through oral presentation.', 130, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('56559f81-7c42-4421-8224-c0188dc74803', 'mathematics', '1', 'Data Handling and Probability', '1.4', 'matching', 'Answer Matching', 'Make notes of students'' reasoning as they match possible answers to questions based on data.', 131, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('50d396ff-5dd4-443a-952c-b8433e700cc2', 'mathematics', '1', 'Data Handling and Probability', '1.4', 'peer-questioning', 'Peer Questioning', 'Students ask each other questions about the graph shown or made.', 132, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('9ada6ad2-d91e-4a62-ac2a-12314c454637', 'mathematics', '1', 'Data Handling and Probability', '1.4', 'conference', 'Information Use', 'Observe, conference, and point the way forward as students make use of information in tables, pictographs, charts to answer questions based on a given data set.', 133, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('e792aa98-a585-471e-947c-cc8548c2b42e', 'mathematics', '1', 'Data Handling and Probability', '1.4', 'observation', 'Re-representation', 'Observe students as they re-represent data given in one mode into another mode of representation (e.g., pictograph to bar chart).', 134, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('8d9cf234-b26c-453b-91ec-998318811682', 'mathematics', '1', 'Data Handling and Probability', '1.4', 'product', 'Graph Transformation', 'Students look at a graph provided by the teacher and make a different graph displaying the same information.', 135, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('813fb19e-33de-4457-89e3-73989f55f799', 'mathematics', '1', 'Data Handling and Probability', '1.4', 'discussion', 'Change Analysis', 'Discuss reasons as to what might have caused the changes in communication devices today.', 136, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('9f6fe3b6-cb81-4e63-af0a-e8d0f8faf752', 'mathematics', '1', 'Data Handling and Probability', '1.4', 'checklist', 'Data Analysis Skills', 'Checklist criteria: Can the student read data from graphs and charts?', 137, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('03f341d1-19f1-47a3-a9d1-db7843e26d82', 'mathematics', '1', 'Data Handling and Probability', '1.4', 'checklist', 'Data Analysis Skills', 'Checklist criteria: Can the student answer questions about data?', 138, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('bfa6b982-225b-4c63-9c4a-a59c4eb418fa', 'mathematics', '1', 'Data Handling and Probability', '1.4', 'checklist', 'Data Analysis Skills', 'Checklist criteria: Can the student use vocabulary (most, least, more than, less than)?', 139, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('901a5af2-d085-4d71-858b-f4af1f539b4d', 'mathematics', '1', 'Data Handling and Probability', '1.4', 'checklist', 'Data Analysis Skills', 'Checklist criteria: Can the student draw conclusions from data?', 140, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('60978153-effe-45be-9112-f751d919322b', 'mathematics', '1', 'Data Handling and Probability', '1.4', 'checklist', 'Data Analysis Skills', 'Checklist criteria: Can the student make informed decisions based on data?', 141, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('3685aedb-65c5-43e9-8282-746d49c5d704', 'mathematics', '1', 'Data Handling and Probability', '1.5', 'oral-questioning', 'Decision Making', 'Students make informed decisions based on outcome.', 142, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('67ec8fdc-e179-4895-911d-bedee3ac1d2a', 'mathematics', '1', 'Data Handling and Probability', '1.5', 'oral-questioning', 'Shopping Scenario', 'Students are presented with a shopping scenario. They are given a certain amount of money and asked to answer particular questions: "What are you certain you can buy?" "Is it likely for you to buy two things with the amount of money you have?"', 143, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('3ce6ac6c-326c-4a1c-b0fd-ceeec6ce62ce', 'mathematics', '1', 'Data Handling and Probability', '1.5', 'oral-questioning', 'Transportation Questions', 'Show students types of transportation and ask questions: "Which type of transportation is likely to be used in your area/country?" "Which type of transportation is unlikely in your area?"', 144, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('2050cc81-024d-4f2a-947b-9b00f89ba401', 'mathematics', '1', 'Data Handling and Probability', '1.5', 'oral-questioning', 'Music Probability', '"Every vehicle on the road has music. What is the possibility of the next vehicle passing with music?"', 145, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('cb688faf-6d90-4c57-8512-61817e4060de', 'mathematics', '1', 'Data Handling and Probability', '1.5', 'online-game', 'Probability Quiz', 'Probability Quiz on Wordwall', 146, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('3a3fee2d-984c-4f0a-a534-c0b4ad732a1f', 'mathematics', '1', 'Data Handling and Probability', '1.5', 'online-game', 'Probability Sort', 'Probability Group Sort on Wordwall', 147, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00');
INSERT INTO curriculum_assessment_strategies (id, subject, grade_level, strand, elo_number, strategy_type, strategy_category, description, sort_order, created_at, updated_at) VALUES
  ('9bc57406-439c-4040-90be-837ea5370f6b', 'mathematics', '1', 'Data Handling and Probability', '1.5', 'online-game', 'Probability Grade 1', 'Probability Grade 1 game: https://wordwall.net/resource/8106684', 148, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('4cc5dff0-925d-401b-89ce-2cf6bcf00742', 'mathematics', '1', 'Data Handling and Probability', '1.5', 'game-based', 'Spinner Game', 'Students spin the wheel and give an example of the word it lands on (maths spinner probability).', 149, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('34e4abac-9c21-4abf-a594-92ad15985f4a', 'mathematics', '1', 'Data Handling and Probability', '1.5', 'game-based', 'Sentence Spinner', 'Students spin the wheel and state whether the sentence is "certain," "impossible," etc.', 150, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('ecc731c2-e228-4154-8e2a-4eaf6678c6a8', 'mathematics', '1', 'Data Handling and Probability', '1.5', 'group-work', 'Chart Creation', 'Students work in groups to create a chart depicting events with outcomes that are possible, impossible, and certain. They take turns to explain why the selected outcomes are placed under the headings they are placed.', 151, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('e295abaa-4996-4de9-a4c3-6c293a972dac', 'mathematics', '1', 'Data Handling and Probability', '1.5', 'checklist', 'Probability', 'Checklist criteria: Can the student use the word "impossible" correctly?', 152, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('c7908b1e-44a7-4d64-a812-e4a5c288e32d', 'mathematics', '1', 'Data Handling and Probability', '1.5', 'checklist', 'Probability', 'Checklist criteria: Can the student use the word "possible" correctly?', 153, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('068cff3e-5dc1-41ec-93c8-03a98957fbb3', 'mathematics', '1', 'Data Handling and Probability', '1.5', 'checklist', 'Probability', 'Checklist criteria: Can the student use the word "certain" correctly?', 154, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('6df77ed0-95a1-436a-b4e6-04cb76d2308a', 'mathematics', '1', 'Data Handling and Probability', '1.5', 'checklist', 'Probability', 'Checklist criteria: Can the student predict outcomes of events?', 155, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('85d22517-2028-4cfe-888b-dc9f7f5d69a5', 'mathematics', '1', 'Data Handling and Probability', '1.5', 'checklist', 'Probability', 'Checklist criteria: Can the student explain reasoning for predictions?', 156, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('aeca458d-6252-4c67-8690-7e5114ba9bf6', 'mathematics', '1', 'Data Handling and Probability', '1.5', 'checklist', 'Probability', 'Checklist criteria: Can the student make informed decisions based on likelihood?', 157, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('92cecc80-ccfa-4097-9f0b-5326536a88c3', 'mathematics', '1', 'Measurement', '1.1', 'diagnostic', 'ELO 1.1 Questions', 'Can the student use vocabulary to describe length (long, short, high, low, near, far)? Can the student use vocabulary to describe capacity (full, empty)? Can the student use vocabulary to describe mass (heavy, light)? Can the student use vocabulary to describe area (large, small)? Can the student classify objects based on measurable attributes?', 158, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('28161ed5-ee9d-4519-ad80-ed05c85186e7', 'mathematics', '1', 'Measurement', '1.2', 'diagnostic', 'ELO 1.2 Questions', 'Can the student compare the length of two objects? Can the student compare the mass of two objects? Can the student compare the capacity of two objects? Can the student compare the area of two objects? Can the student explain reasoning for comparisons? Does the student use a common start point when comparing length?', 159, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('fba4c2bc-ddc7-4768-8c4b-4f2bd023a7aa', 'mathematics', '1', 'Measurement', '1.3', 'diagnostic', 'ELO 1.3 Questions', 'Can the student select appropriate non-standard units? Can the student estimate before measuring? Can the student measure using body parts? Can the student measure using objects? Can the student explain differences in measurements? Does the student understand why different people get different measurements?', 160, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('4f9ef843-3d77-4337-a94e-ab30d85ef85e', 'mathematics', '1', 'Measurement', '1.4', 'diagnostic', 'ELO 1.4 Questions', 'Can the student state the days of the week in order? Can the student state the months of the year in order? Can the student read a calendar? Can the student tell time on the hour? Can the student tell time at half past? Can the student identify coins and their values? Can the student combine coins to make a given value?', 161, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('a0d90417-73ef-462b-8581-b3445b4a0f8a', 'mathematics', '1', 'Data Handling and Probability', '1.1', 'diagnostic', 'ELO 1.1 Questions', 'Can the student formulate questions based on observation? Can the student identify what information a question will collect? Can the student identify sources for collecting data? Are the student''s questions related to what was observed?', 162, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('6a78786d-6c27-46dd-b36b-7d8804860497', 'mathematics', '1', 'Data Handling and Probability', '1.2', 'diagnostic', 'ELO 1.2 Questions', 'Can the student sort objects by one attribute? Can the student explain why objects were sorted a certain way? Can the student collect data through observation? Can the student record data using tally marks? Can the student create a pictograph? Can the student create a bar graph?', 163, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('9e449b43-4bd8-494c-b2ce-b5511c4808ca', 'mathematics', '1', 'Data Handling and Probability', '1.3', 'diagnostic', 'ELO 1.3 Questions', 'Can the student order data from greatest to least? Can the student identify the highest and lowest values? Can the student compare values in a data set? Can the student explain strategies used for ordering?', 164, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('f01485b1-185e-4ee5-bf36-b8441ab631a4', 'mathematics', '1', 'Data Handling and Probability', '1.4', 'diagnostic', 'ELO 1.4 Questions', 'Can the student read data from graphs and charts? Can the student answer questions about data? Can the student use vocabulary (most, least, more than, less than)? Can the student draw conclusions from data? Can the student make informed decisions based on data?', 165, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00'),
  ('81ac6f12-1cff-4277-a861-72e8ed2dce53', 'mathematics', '1', 'Data Handling and Probability', '1.5', 'diagnostic', 'ELO 1.5 Questions', 'Can the student use "impossible," "possible," and "certain" correctly? Can the student predict outcomes of events? Can the student explain why an event is likely or unlikely? Can the student make informed decisions based on probability?', 166, '2026-01-06T12:47:56.138137+00:00', '2026-01-06T12:47:56.138137+00:00');
